1	import * as THREE from "three";
2	import { createTerrain } from "./terrain.js";
3	import { createFirstPerson } from "./firstPerson.js";
4	import { FRAGMENTS, BUILDERS } from "./debris.js";
5	
6	// The walkable island level — LEVEL 1 ("First Memories").
7	//
8	// A Diner-Dash-style loop, one memory at a time, driven by the REAL workflow
9	// typed into the ship's terminal:
10	//   walk up → terminal opens → `git add` (stage) → `git commit` (freeze in ice)
11	//   → Entire offers to link a checkpoint → press y → ship memory restores.
12	// When every memory is linked → run `entire checkpoint list` to review them all.
13	//
14	// PRESSURE: a single level countdown runs the whole time. Bank every memory
15	// before it hits zero, or the un-banked memories melt away and the run fails
16	// (press R to retry). One clock for the whole level — not per-memory.
17	//
18	// Teaching: a commit just freezes the change; linking a CHECKPOINT (the y/n
19	// offer Entire makes after a commit) is what restores it to the ship's memory.
20	
21	const INTERACT_DIST = 8;    // how close (XZ) to open a memory's terminal
22	const TOTAL_TIME = 45;      // seconds to recover & bank EVERY memory (tunable — scary-tight)
23	const MELT_DUR = 1.8;       // seconds the lost memories take to melt away
24	const LOW_TIME = 22;        // clock turns urgent (red, pulsing) under this many seconds
25	const CRIT_TIME = 8;        // clock goes CRITICAL (fast pulse) under this many seconds
26	const PANIC_TIME = 22;      // the SKY starts shifting toward panic-red under this many seconds
27	const MEMORY_COUNT = 3;     // calm tutorial: three memories
28	const BEAM_COLOR = 0xffd27a;
29	
30	// Sky panic palette — the whole world reddens as the clock runs out.
31	const SKY_CALM  = new THREE.Color(0x2a2350);  // lavender dusk (the resting sky/fog)
32	const SKY_PANIC = new THREE.Color(0x6e0f16);  // angry crimson
33	const FOG_PANIC = new THREE.Color(0x4a0a0e);  // deep blood fog closing in
34	const DOME_CALM = new THREE.Color(0x3a3168);
35	const DOME_PANIC = new THREE.Color(0x7a141c);
36	const SUN_CALM  = new THREE.Color(0xfff1dc);  // warm sun
37	const SUN_PANIC = new THREE.Color(0xff5a3c);  // hot red alarm light
38	
39	// Where each memory surfaces on the island (world XZ).
40	const PLACEMENTS = [
41	  { x: -34, z: -28 },
42	  { x: 40, z: -18 },
43	  { x: 28, z: 38 },
44	  { x: -30, z: 36 },
45	];
46	
47	// What the terminal asks for at each stage of a memory's recovery.
48	const STEPS = {
49	  dormant:   { type: "command", cmd: "git add",    accept: ["git add"],    hint: "Stage the recovered memory" },
50	  recovered: { type: "command", cmd: "git commit", accept: ["git commit"], hint: "Commit it before the clock runs out" },
51	  frozen:    { type: "confirm", question: "Link this commit to a checkpoint?",
52	               hint: "Entire offers to capture the session behind this commit" },
53	};
54	// After every memory is linked, the player reviews them with this command.
55	const REVIEW_STEP = {
56	  type: "command", cmd: "entire checkpoint list", accept: ["entire checkpoint list"],
57	  hint: "All memories recovered — review what you've banked",
58	};
59	
60	function normalizeCmd(s) {
61	  return s.trim().toLowerCase().replace(/\s+/g, " ");
62	}
63	function cmdMatches(input, accepts) {
64	  const n = normalizeCmd(input);
65	  return accepts.some((a) => n === a || n.startsWith(a + " "));
66	}
67	
68	function makeBeamTexture() {
69	  const c = document.createElement("canvas");
70	  c.width = 8; c.height = 128;
71	  const ctx = c.getContext("2d");
72	  const g = ctx.createLinearGradient(0, 0, 0, 128);
73	  g.addColorStop(0, "rgba(255,210,122,0)");
74	  g.addColorStop(1, "rgba(255,210,122,0.9)");
75	  ctx.fillStyle = g;
76	  ctx.fillRect(0, 0, 8, 128);
77	  const t = new THREE.CanvasTexture(c);
78	  t.colorSpace = THREE.SRGBColorSpace;
79	  return t;
80	}
81	
82	// Translucent crystal that encases a memory once it's committed.
83	function makeIceBlock() {
84	  const geo = new THREE.IcosahedronGeometry(3.4, 0);
85	  const mat = new THREE.MeshPhysicalMaterial({
86	    color: 0xbfe9ff,
87	    metalness: 0,
88	    roughness: 0.06,
89	    transmission: 0.5,
90	    thickness: 2.6,
91	    ior: 1.3,
92	    transparent: true,
93	    opacity: 0.62,
94	    emissive: 0x0a2230,
95	    emissiveIntensity: 0.35,
96	    flatShading: true,
97	  });
98	  return new THREE.Mesh(geo, mat);
99	}
100	
101	// Floating label above a frozen block — the commit trailer Entire stamps on:
102	//   "Entire-Checkpoint: <12-char hash>" (dim key + bright hash).
103	function makeIdSprite(id) {
104	  const c = document.createElement("canvas");
105	  c.width = 768; c.height = 64;
106	  const ctx = c.getContext("2d");
107	  ctx.font = "bold 28px ui-monospace, monospace";
108	  ctx.textBaseline = "middle";
109	  ctx.shadowColor = "rgba(111,227,255,0.9)";
110	  ctx.shadowBlur = 14;
111	
112	  const key = "Entire-Checkpoint: ";
113	  const keyW = ctx.measureText(key).width;
114	  const idW = ctx.measureText(id).width;
115	  let x = (c.width - (keyW + idW)) / 2;       // center the whole trailer
116	  ctx.textAlign = "left";
117	  ctx.fillStyle = "#8fc4dc";                    // dim trailer key
118	  ctx.fillText(key, x, 34);
119	  ctx.fillStyle = "#dff3ff";                    // bright hash
120	  ctx.fillText(id, x + keyW, 34);
121	
122	  const tex = new THREE.CanvasTexture(c);
123	  tex.colorSpace = THREE.SRGBColorSpace;
124	  const spr = new THREE.Sprite(new THREE.SpriteMaterial({
125	    map: tex, transparent: true, depthWrite: false, fog: false,
126	  }));
127	  spr.scale.set(30, 2.5, 1);                    // 12:1 canvas → keep text height
128	  return spr;
129	}
130	
131	// Entire checkpoints get a 12-character hex id (e.g. 711044b1fe29).
132	function genCheckpointId() {
133	  const hex = "0123456789abcdef";
134	  let s = "";
135	  for (let i = 0; i < 12; i++) s += hex[Math.floor(Math.random() * 16)];
136	  return s;
137	}
138	
139	export function createIslandView(renderer, { onExit } = {}) {
140	  const canvas = renderer.domElement;
141	
142	  // ---------- scene & sky ----------
143	  const scene = new THREE.Scene();
144	  scene.background = new THREE.Color(0x2a2350); // lavender dusk sky
145	  scene.fog = new THREE.Fog(0x2a2350, 90, 320);
146	
147	  const camera = new THREE.PerspectiveCamera(
148	    62, window.innerWidth / window.innerHeight, 0.1, 2000
149	  );
150	
151	  // ---------- lighting (soft, warm sun in a lavender sky) ----------
152	  scene.add(new THREE.HemisphereLight(0xcdbcff, 0x3a2f5e, 0.7));
153	  const sun = new THREE.DirectionalLight(0xfff1dc, 1.5);
154	  sun.position.set(60, 90, 40);
155	  scene.add(sun);
156	  scene.add(new THREE.AmbientLight(0x6a5a92, 0.3));
157	
158	  const dome = new THREE.Mesh(
159	    new THREE.SphereGeometry(900, 32, 16),
160	    new THREE.MeshBasicMaterial({ color: 0x3a3168, side: THREE.BackSide, fog: false })
161	  );
162	  scene.add(dome);
163	
164	  // ---------- terrain ----------
165	  const terrain = createTerrain({ size: 200, segments: 220, maxHeight: 26, seed: 1337 });
166	  scene.add(terrain.mesh, terrain.water);
167	
168	  // ---------- memories ----------
169	  const beamTex = makeBeamTexture();
170	  const artifacts = [];
171	  FRAGMENTS.slice(0, MEMORY_COUNT).forEach((frag, idx) => {
172	    const place = PLACEMENTS[idx % PLACEMENTS.length];
173	    const groundY = terrain.heightAt(place.x, place.z);
174	    const anchor = new THREE.Group();
175	    anchor.position.set(place.x, groundY, place.z);
176	
177	    const model = BUILDERS[frag.kind]();
178	    model.scale.setScalar(14);
179	    model.position.y = 1.4;
180	    anchor.add(model);
181	
182	    // A tall light beam so the memory is findable from across the island.
183	    const beam = new THREE.Mesh(
184	      new THREE.CylinderGeometry(0.6, 0.6, 60, 12, 1, true),
185	      new THREE.MeshBasicMaterial({
186	        map: beamTex, color: BEAM_COLOR, transparent: true, opacity: 0.5,
187	        blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide,
188	        fog: false,
189	      })
190	    );
191	    beam.position.y = 30;
192	    anchor.add(beam);
193	
194	    const glow = new THREE.PointLight(BEAM_COLOR, 8, 40, 2);
195	    glow.position.y = 3;
196	    anchor.add(glow);
197	
198	    scene.add(anchor);
199	    artifacts.push({
200	      anchor, model, beam, glow, fragment: frag,
201	      state: "dormant",   // dormant → recovered (staged) → frozen (committed) → checkpointed
202	      ice: null, idSprite: null, core: null, id: null, iceY: 0,
203	      melting: false, meltT: 0,   // melt-away animation when the level times out
204	      bobOff: Math.random() * 10,
205	    });
206	  });
207	
208	  // ---------- first-person controller ----------
209	  const fp = createFirstPerson(camera, canvas, {
210	    heightAt: terrain.heightAt,
211	    radius: terrain.radius * 0.96,
212	    eyeHeight: 2.6,
213	    speed: 24,
214	  });
215	  scene.add(fp.controls.object);
216	
217	  // ---------- HUD elements ----------
218	  const promptEl = document.getElementById("fp-prompt");
219	  const controlsEl = document.getElementById("fp-controls");
220	  const crosshair = document.getElementById("crosshair");
221	  const islandHud = document.getElementById("island-hud");
222	  const tutorialEl = document.getElementById("tutorial");
223	  const actionBar = document.getElementById("action-bar");
224	  const actionBarFill = document.getElementById("action-bar-fill");
225	  const shipMeter = document.getElementById("ship-meter");
226	  const shipMeterFill = document.getElementById("ship-meter-fill");
227	  const shipMeterPct = document.getElementById("ship-meter-pct");
228	  const ckptCard = document.getElementById("ckpt-card");
229	  const ccId = document.getElementById("cc-id");
230	  const ccSummary = document.getElementById("cc-summary");
231	  const ccAttrFill = document.getElementById("cc-attr-fill");
232	  const ccAttrText = document.getElementById("cc-attr-text");
233	  const termEl = document.getElementById("terminal");
234	  const termHint = document.getElementById("term-hint");
235	  const termInput = document.getElementById("term-input");
236	  const termList = document.getElementById("term-list");
237	  const termMsg = document.getElementById("term-msg");
238	  const termCta = document.getElementById("term-cta");
239	  const countdownEl = document.getElementById("countdown");
240	  const countdownTime = document.getElementById("countdown-time");
241	  const levelFail = document.getElementById("level-fail");
242	  const briefingEl = document.getElementById("briefing");
243	  const briefingStartBtn = document.getElementById("briefing-start");
244	
245	  let target = null;            // nearest memory in range
246	  let active = false;           // is this view being shown?
247	  let promptText = null;
248	  let controlsLocked = null;
249	  const taught = new Set();
250	  let tutorialTimer = null;
251	  let cardTimer = null;
252	  let msgTimer = null;
253	
254	  // Terminal state
255	  let terminalOpen = false;
256	  let termTarget = null;        // the memory whose terminal is open
257	  let buffer = "";              // what the player has typed
258	  let dismissedMemory = null;   // memory the player Esc'd out of (until they leave)
259	  let reviewMode = false;       // all linked → review with `entire checkpoint list`
260	  let listShown = false;        // the list has been printed
261	
262	  // Level countdown — the single source of pressure for the whole run.
263	  let timeLeft = TOTAL_TIME;
264	  let timerRunning = false;
265	  let failed = false;
266	  let started = false;          // briefing dismissed → movement + clock go live
267	
268	  const checkpointedCount = () =>
269	    artifacts.filter((a) => a.state === "checkpointed").length;
270	  const allLinked = () => checkpointedCount() >= artifacts.length;
271	
272	  // ---------- HUD helpers ----------
273	  function setPrompt(text) {
274	    if (!promptEl || text === promptText) return;
275	    promptText = text;
276	    if (text) { promptEl.textContent = text; promptEl.classList.remove("hidden"); }
277	    else promptEl.classList.add("hidden");
278	  }
279	  function hideActionBar() { actionBar.classList.add("hidden"); }
280	
281	  // ---------- level countdown ----------
282	  function fmtTime(s) {
283	    s = Math.max(0, Math.ceil(s));
284	    return `${Math.floor(s / 60)}:${String(s % 60).padStart(2, "0")}`;
285	  }
286	  function updateClock() {
287	    if (countdownTime) countdownTime.textContent = fmtTime(timeLeft);
288	    countdownEl?.classList.toggle("is-low", timerRunning && timeLeft <= LOW_TIME);
289	    countdownEl?.classList.toggle("is-critical", timerRunning && timeLeft <= CRIT_TIME);
290	  }
291	
292	  // How hard the sky is panicking right now: 0 = calm lavender, 1 = full crimson throb.
293	  function panicFactor() {
294	    if (failed) return 1;                         // hold the dread behind the fail screen
295	    if (!timerRunning || timeLeft > PANIC_TIME) return 0;
296	    let p = (PANIC_TIME - timeLeft) / PANIC_TIME; // 0 at PANIC_TIME → 1 at 0:00
297	    p *= p;                                        // eased: barely there early, harsh late
298	    if (timeLeft <= CRIT_TIME) {                   // throb once it's critical
299	      const throb = 0.5 + 0.5 * Math.sin(performance.now() / 85);
300	      p += 0.14 * throb;
301	    }
302	    return Math.min(1, p);
303	  }
304	  function applyPanicSky() {
305	    const p = panicFactor();
306	    scene.background.copy(SKY_CALM).lerp(SKY_PANIC, p);
307	    scene.fog.color.copy(SKY_CALM).lerp(FOG_PANIC, p);
308	    dome.material.color.copy(DOME_CALM).lerp(DOME_PANIC, p);
309	    sun.color.copy(SUN_CALM).lerp(SUN_PANIC, p * 0.85);
310	  }
311	  function failLevel() {
312	    if (failed) return;
313	    failed = true;
314	    timerRunning = false;
315	    closeTerminal(false);
316	    fp.detach();                  // freeze the player behind the fail screen
317	    // Un-banked memories always melt; if they ran out the clock on the final
318	    // `entire checkpoint list` (all banked, not yet reviewed), the whole run melts.
319	    for (const a of artifacts) {
320	      if (reviewMode || a.state !== "checkpointed") { a.melting = true; a.meltT = MELT_DUR; }
321	    }
322	    countdownEl?.classList.remove("is-low", "is-critical");
323	    tutorialEl?.classList.add("hidden");
324	    levelFail?.classList.remove("hidden");
325	  }
326	  function resetLevel() {
327	    failed = false;
328	    levelFail?.classList.add("hidden");
329	    if (active) fp.attach();      // movement resumes for the new run
330	    for (const a of artifacts) {
331	      if (a.ice) { a.anchor.remove(a.ice); a.ice = null; }
332	      if (a.idSprite) { a.anchor.remove(a.idSprite); a.idSprite = null; }
333	      if (a.core) { a.anchor.remove(a.core); a.core = null; }
334	      a.state = "dormant";
335	      a.id = null;
336	      a.melting = false; a.meltT = 0;
337	      a.model.position.y = 1.4;
338	      setModelOpacity(a.model, 1);
339	    }
340	    reviewMode = false;
341	    listShown = false;
342	    dismissedMemory = null;
343	    shipMeter?.classList.remove("is-full");
344	    setPower();
345	    timeLeft = TOTAL_TIME;
346	    timerRunning = true;
347	    updateClock();
348	    showTutorial("New attempt — bank all three memories before the clock hits zero.", 4500);
349	  }
350	
351	  // Landing briefing — the level is frozen (no clock, no movement) until START.
352	  function showBriefing() {
353	    timerRunning = false;
354	    fp.detach();
355	    tutorialEl?.classList.add("hidden");
356	    briefingEl?.classList.remove("hidden");
357	  }
358	  function startLevel() {
359	    if (started) return;
360	    started = true;
361	    briefingEl?.classList.add("hidden");
362	    fp.attach();
363	    timeLeft = TOTAL_TIME;
364	    timerRunning = true;
365	    updateClock();
366	    showTutorial("Memories are surfacing — the clock's short. Bank all three before 0:00!", 6500);
367	  }
368	  briefingStartBtn?.addEventListener("click", startLevel);
369	
370	  function showTutorial(text, ms = 5500) {
371	    if (!tutorialEl) return;
372	    clearTimeout(tutorialTimer);
373	    tutorialEl.textContent = text;
374	    tutorialEl.classList.remove("hidden");
