378	    if (taught.has(key)) return;
379	    taught.add(key);
380	    showTutorial(text, ms);
381	  }
382	
383	  function setPower() {
384	    const pct = Math.round((checkpointedCount() / artifacts.length) * 100);
385	    // Vertical gauge — fills bottom-up and shifts color as memory is restored.
386	    if (shipMeterFill) shipMeterFill.style.height = pct + "%";
387	    if (shipMeterPct) shipMeterPct.textContent = pct + "%";
388	    if (shipMeter) {
389	      shipMeter.classList.toggle("lvl-low", pct > 0 && pct <= 34);
390	      shipMeter.classList.toggle("lvl-mid", pct > 34 && pct < 100);
391	      shipMeter.classList.toggle("lvl-high", pct >= 100);
392	    }
393	  }
