403	  }
404	
405	  function setControls(locked) {
406	    if (!controlsEl) return;
407	    if (locked === controlsLocked && !controlsEl.classList.contains("hidden")) return;
408	    controlsLocked = locked;
409	    controlsEl.innerHTML = `
410	      <span class="control-item">
411	        <span class="control-label">To move</span>
412	        <span class="arrow-keys" aria-label="Arrow keys">
413	          <span class="key key-up">↑</span>
414	          <span class="key key-left">←</span>
415	          <span class="key key-down">↓</span>
416	          <span class="key key-right">→</span>
417	        </span>
418	      </span>
419	      ${locked ? `
420	        <span class="control-item">
421	          <span class="control-label">To look around</span>
422	          <span class="mouse-hint">
423	            <span class="mouse-icon" aria-hidden="true"></span>
424	            <span>move mouse</span>
425	          </span>
426	        </span>
427	      ` : ""}
428	      <span class="control-item">
429	        <span class="control-label">Return to orbit</span>
430	        <span class="key">B</span>
431	      </span>
432	    `;
433	    controlsEl.classList.remove("hidden");
434	  }
435	  function hideControls() {
436	    controlsLocked = null;
437	    controlsEl?.classList.add("hidden");
438	  }
439	
440	  function setModelOpacity(model, o) {
441	    model.traverse((n) => {
442	      if (n.material) { n.material.transparent = o < 1; n.material.opacity = o; }
443	    });
444	  }
445	
446	  // ---------- terminal ----------
447	  function currentStep() {
448	    if (reviewMode) return REVIEW_STEP;
449	    if (!termTarget) return null;
450	    return STEPS[termTarget.state] || null;
451	  }
452	  function renderTerminal() {
453	    const step = currentStep();
454	    if (!step) return;
455	
456	    if (reviewMode && listShown) {
457	      termHint.textContent = "# entire checkpoint list";
458	      termInput.textContent = "entire checkpoint list";
459	      termInput.classList.remove("is-dim");
460	      if (termCta) termCta.innerHTML = "";
461	      termList?.classList.remove("hidden");
462	      return;
463	    }
464	    termList?.classList.add("hidden");
465	
466	    // The hint is just the "why"; the actionable command/keys live in the CTA
467	    // below the input line, where they're the most prominent thing on screen.
468	    termHint.textContent = step.hint ? `# ${step.hint}` : "";
469	    if (step.type === "confirm") {
470	      termInput.textContent = `${step.question}  [y/n]`;
471	      termInput.classList.add("is-dim");
472	      if (termCta) termCta.innerHTML =
473	        `<span class="cta-label">PRESS</span>` +
474	        `<kbd class="cta-key cta-key-yes">Y</kbd><span class="cta-note">link checkpoint</span>` +
475	        `<kbd class="cta-key cta-key-no">N</kbd><span class="cta-note">skip</span>`;
476	    } else {
477	      termInput.textContent = buffer;
478	      termInput.classList.remove("is-dim");
479	      if (termCta) termCta.innerHTML =
480	        `<span class="cta-label">TYPE</span><span class="cta-cmd">${step.cmd}</span>`;
481	    }
482	  }
483	  function flashTerminal(text, ok) {
484	    if (!termMsg) return;
485	    clearTimeout(msgTimer);
486	    termMsg.textContent = text;
487	    termMsg.classList.remove("show-ok", "show-err");
488	    termMsg.classList.add(ok ? "show-ok" : "show-err");
489	    msgTimer = setTimeout(() => termMsg.classList.remove("show-ok", "show-err"), 2400);
490	  }
491	  function openTerminal(a) {
492	    if (terminalOpen) return;
493	    terminalOpen = true;
494	    termTarget = a;
495	    buffer = "";
496	    fp.detach();                      // freeze movement; keystrokes feed the terminal
497	    termMsg?.classList.remove("show-ok", "show-err");
498	    termList?.classList.add("hidden");
499	    termEl?.classList.remove("hidden");
500	    renderTerminal();
501	  }
502	  function closeTerminal(dismiss) {
503	    if (!terminalOpen) return;
504	    if (dismiss && termTarget) dismissedMemory = termTarget;
505	    terminalOpen = false;
506	    termTarget = null;
507	    buffer = "";
508	    termEl?.classList.add("hidden");
509	    if (active) fp.attach();          // resume walking (addEventListener dedupes)
510	  }
511	  function submitCommand() {
512	    const step = currentStep();
513	    if (!step || step.type !== "command" || listShown) return;
514	    if (cmdMatches(buffer, step.accept)) {
515	      buffer = "";
516	      if (reviewMode) { showCheckpointList(); return; }
517	      runStep(termTarget);            // dormant → stage, recovered → commit
518	      flashTerminal("✓ ok", true);
519	      renderTerminal();
520	    } else {
521	      flashTerminal(`command not recognized — try:  ${step.cmd}`, false);
522	      buffer = "";
523	      renderTerminal();
524	    }
525	  }
526	  function showCheckpointList() {
527	    listShown = true;
528	    timerRunning = false;            // the run is complete — NOW the clock stops
529	    countdownEl?.classList.remove("is-low", "is-critical");
530	    if (termList) {
531	      termList.innerHTML = artifacts.map((a) =>
532	        `<div class="term-list-row"><span class="tl-id">` +
533	        `<span class="tl-key">Entire-Checkpoint:</span> ${a.id}</span>` +
534	        `<span class="tl-title">recovered: ${a.fragment.title}</span></div>`
535	      ).join("");
536	    }
537	    flashTerminal(`${artifacts.length} checkpoints linked · ship memory restored`, true);
538	    showTutorial("Memory restored — the ship knows the way home. Press Esc to close the terminal, then B to return to orbit.", 0);
539	    renderTerminal();
540	  }
541	
542	  // ---------- state transitions ----------
543	  function runStep(a) {
544	    if (a.state === "dormant") stage(a);
545	    else if (a.state === "recovered") commit(a);
546	  }
547	  function stage(a) {
548	    a.state = "recovered";
549	    teachOnce("staged",
550	      "Recovered and staged. Run `git commit` to freeze it — the clock is ticking.");
551	  }
552	  function commit(a) {
553	    a.state = "frozen";
554	    setModelOpacity(a.model, 1);
555	    const ice = makeIceBlock();
556	    ice.position.y = a.model.position.y + 0.6;
557	    a.iceY = ice.position.y;
558	    a.anchor.add(ice);
559	    a.ice = ice;
560	    teachOnce("committed",
561	      "Committed and frozen — locked in. Now Entire offers to link a checkpoint: press y to capture the session behind this commit.");
562	  }
563	  function confirmCheckpoint(yes) {
564	    const a = termTarget;
565	    if (!a || a.state !== "frozen") return;
566	    if (!yes) {
567	      flashTerminal("declined — without a checkpoint the ship can't track this commit. re-approach to link it.", false);
568	      closeTerminal(true);
569	      return;
570	    }
571	    checkpoint(a);
572	    if (allLinked()) {
573	      reviewMode = true;             // clock KEEPS running — the list is the finish line
574	      shipMeter?.classList.add("is-full");
575	      showTutorial("All banked! Now type `entire checkpoint list` before the clock hits 0:00 — hurry!", 0);
576	      renderTerminal();              // stay open → review step
577	    } else {
578	      closeTerminal(false);
579	    }
580	  }
581	  function checkpoint(a) {
582	    a.state = "checkpointed";
583	    a.id = genCheckpointId();
584	    const shipPct = 62 + Math.floor(Math.random() * 23); // 62–84%
585	
586	    if (a.ice) {
587	      a.ice.material.emissive.setHex(0x2a6c8a);
588	      a.ice.material.emissiveIntensity = 1.1;
589	      const core = new THREE.PointLight(0x8fe3ff, 6, 26, 2);
590	      core.position.copy(a.ice.position);
591	      a.anchor.add(core);
592	      a.core = core;
593	    }
594	    const spr = makeIdSprite(a.id);
595	    spr.position.y = a.iceY + 5;
596	    a.anchor.add(spr);
597	    a.idSprite = spr;
598	
599	    showCard(a, shipPct);
600	    setPower();
601	    teachOnce("checkpointed",
602	      "Checkpoint linked — Entire stamps it onto the commit via an `Entire-Checkpoint` trailer, and the ship remembers a little more.");
603	  }
604	
605	  // ---------- input ----------
606	  function onCanvasClick() {
607	    if (!started) return;                 // briefing up — ignore world clicks
608	    if (active && !fp.isLocked) fp.lock();
609	  }
610	  function onKeyDown(e) {
611	    if (!active) return;
612	
613	    // Landing briefing is up — Enter/Space begins the run, nothing else.
614	    if (!started) {
615	      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
616	      return;
617	    }
618	
619	    // The run failed — only R (retry) does anything.
620	    if (failed) {
621	      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
622	      return;
623	    }
624	
625	    // While the terminal is open, all keys feed it.
626	    if (terminalOpen) {
627	      if (e.code === "Escape") {
628	        // No bailing on the final review — the clock is still ticking.
629	        if (reviewMode && !listShown) { e.preventDefault(); return; }
630	        closeTerminal(true); e.preventDefault(); return;
631	      }
632	      if (reviewMode && listShown) { e.preventDefault(); return; } // only Esc closes the list
633	
634	      const step = currentStep();
635	      if (step?.type === "confirm") {
636	        if (e.key === "y" || e.key === "Y") { confirmCheckpoint(true); e.preventDefault(); return; }
637	        if (e.key === "n" || e.key === "N") { confirmCheckpoint(false); e.preventDefault(); return; }
638	        e.preventDefault();
639	        return;
640	      }
641	      // command mode
642	      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
643	      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
644	      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
645	        buffer += e.key;
646	        renderTerminal();
647	        e.preventDefault();
648	      }
649	      return;
650	    }
651	
652	    // Walking around (terminal closed).
653	    if (e.code === "Escape" && fp.isLocked) fp.unlock();
654	    if (e.code === "KeyB") onExit?.();
655	  }
656	  fp.controls.addEventListener("lock", () => crosshair?.classList.remove("hidden"));
657	  fp.controls.addEventListener("unlock", () => crosshair?.classList.add("hidden"));
658	
659	  // ---------- HUD per-frame ----------
660	  function refreshHud() {
661	    if (!started || terminalOpen) {     // briefing up or terminal open → no walk HUD
662	      setPrompt(null);
663	      hideControls();
664	      hideActionBar();
665	      return;
666	    }
667	    setControls(fp.isLocked);
668	    hideActionBar();
669	    if (!fp.isLocked) { setPrompt("Click to look around"); return; }
670	    if (listShown) { setPrompt("Memory restored — press B to return to orbit"); return; }
671	    setPrompt("Find the surfacing memory");
672	  }
673	
674	  // ---------- per-frame ----------
675	  function update(dt, t) {
676	    fp.update(dt);
677	
678	    // Level countdown — one clock for the whole run.
679	    if (active && timerRunning && !failed) {
680	      timeLeft = Math.max(0, timeLeft - dt);
681	      updateClock();
682	      if (timeLeft <= 0) failLevel();
683	    }
684	    applyPanicSky();   // the sky reacts to the clock every frame
685	
686	    // Nearest memory within reach (ignoring height).
687	    let nearest = null, nd = Infinity;
688	    for (const a of artifacts) {
689	      const dx = camera.position.x - a.anchor.position.x;
690	      const dz = camera.position.z - a.anchor.position.z;
691	      const d = Math.hypot(dx, dz);
692	      if (d < nd) { nd = d; nearest = a; }
693	    }
694	    target = nd <= INTERACT_DIST ? nearest : null;
695	
696	    // Auto open/close the ship's terminal as you reach a memory.
697	    // (In review mode the terminal is driven manually, so leave it alone.)
698	    if (active && started && !reviewMode && !failed) {
699	      if (dismissedMemory && target !== dismissedMemory) dismissedMemory = null;
700	      const canOpen = target && target.state !== "checkpointed" && target !== dismissedMemory;
701	      if (canOpen && !terminalOpen) openTerminal(target);
702	      else if (!canOpen && terminalOpen) closeTerminal(false);
703	    }
704	
705	    for (const a of artifacts) {
706	      // Melting away after a time-out — sink and fade, then disappear.
707	      if (a.melting) {
708	        a.meltT = Math.max(0, a.meltT - dt);
709	        const k = a.meltT / MELT_DUR;
710	        setModelOpacity(a.model, k);
711	        a.model.position.y -= dt * 2.4;
712	        if (a.ice) a.ice.material.opacity = 0.62 * k;
713	        a.beam.visible = false;
714	        a.glow.visible = false;
715	        continue;
716	      }
717	
718	      const encased = a.state === "frozen" || a.state === "checkpointed";
719	
720	      // Idle spin/bob until the memory is encased in ice.
721	      if (!encased) {
722	        a.model.rotation.y += dt * 0.6;
723	        a.model.position.y = 1.4 + Math.sin((t + a.bobOff) * 1.5) * 0.4;
724	        setModelOpacity(a.model, 1);
725	      }
726	
727	      // Beam + glow: bright while findable, gone once frozen.
728	      const lit = a.state === "dormant" || a.state === "recovered";
729	      let o = 0;
730	      if (a.state === "dormant") o = 0.4 + Math.sin(t * 2) * 0.12;
731	      else if (a.state === "recovered") o = 0.22;
732	      a.beam.material.opacity = o;
733	      a.beam.visible = o > 0.01;
734	      a.glow.visible = lit;
735	    }
736	
737	    if (terminalOpen) renderTerminal(); // reflect fade-driven state changes
738	    if (active) refreshHud();
739	  }
740	
741	  // ---------- lifecycle ----------
742	  function enter() {
743	    active = true;
744	    fp.groundAt(0, terrain.radius * 0.75);
745	    camera.lookAt(0, terrain.heightAt(0, 0) + 6, 0);
746	    canvas.addEventListener("click", onCanvasClick);
747	    window.addEventListener("keydown", onKeyDown);
748	    islandHud?.classList.remove("hidden");
749	    setControls(false);
750	    crosshair?.classList.add("hidden");
751	    setPower();
752	    if (!started) {                 // fresh landing — read the briefing, then START
753	      showBriefing();
754	    } else if (listShown) {         // truly done — the list has been run
755	      fp.attach();
756	      timerRunning = false;
757	      showTutorial("Memory restored — press B to return to orbit.", 0);
758	    } else if (failed) {
759	      resetLevel();                 // came back after a wipe → fresh run
760	    } else {
761	      fp.attach();
762	      timerRunning = true;          // resume the level clock
763	      if (reviewMode) {             // resume the timed final review
764	        openTerminal(artifacts[0]); // termTarget unused in review; reopens the prompt
765	        showTutorial("Type `entire checkpoint list` before the clock hits 0:00!", 0);
766	      } else {
767	        showTutorial("Memories are surfacing — the clock's short. Bank all three before 0:00!", 6500);
768	      }
769	    }
770	    updateClock();
771	    applyPanicSky();   // start on the right sky (calm unless we resumed low on time)
772	  }
773	  function exit() {
774	    active = false;
775	    timerRunning = false;           // pause the clock while in orbit
776	    closeTerminal(false);
777	    fp.unlock();
778	    fp.detach();
779	    canvas.removeEventListener("click", onCanvasClick);
780	    window.removeEventListener("keydown", onKeyDown);
781	    setPrompt(null);
782	    hideControls();
783	    hideActionBar();
784	    tutorialEl?.classList.add("hidden");
785	    ckptCard?.classList.add("hidden");
786	    termEl?.classList.add("hidden");
787	    levelFail?.classList.add("hidden");
788	    briefingEl?.classList.add("hidden");
789	    islandHud?.classList.add("hidden");
790	    crosshair?.classList.add("hidden");
791	  }
792	  function resize() {
793	    camera.aspect = window.innerWidth / window.innerHeight;
794	    camera.updateProjectionMatrix();
795	  }
796	
797	  return { scene, camera, update, enter, exit, resize };
798	}
