1	import * as THREE from "three";
2	
3	// Radial-gradient sprite used as the attention halo under each debris item.
4	function makeHaloTexture(color = "#6fe3ff") {
5	  const s = 128;
6	  const c = document.createElement("canvas");
7	  c.width = c.height = s;
8	  const ctx = c.getContext("2d");
9	  const g = ctx.createRadialGradient(s / 2, s / 2, 0, s / 2, s / 2, s / 2);
10	  g.addColorStop(0, color);
11	  g.addColorStop(0.25, color);
12	  g.addColorStop(1, "rgba(0,0,0,0)");
13	  ctx.fillStyle = g;
14	  ctx.fillRect(0, 0, s, s);
15	  const t = new THREE.CanvasTexture(c);
16	  t.colorSpace = THREE.SRGBColorSpace;
17	  return t;
18	}
19	
20	const HALO_TEX = { value: null };
21	function haloTexture() {
22	  if (!HALO_TEX.value) HALO_TEX.value = makeHaloTexture();
23	  return HALO_TEX.value;
24	}
25	
26	// ---- tiny model builders for each kind of debris ----
27	function buildHelmet() {
28	  const g = new THREE.Group();
29	  const glass = new THREE.Mesh(
30	    new THREE.SphereGeometry(0.06, 24, 24),
31	    new THREE.MeshStandardMaterial({ color: 0x223344, metalness: 0.3, roughness: 0.15 })
32	  );
33	  const ring = new THREE.Mesh(
34	    new THREE.TorusGeometry(0.06, 0.015, 12, 24),
35	    new THREE.MeshStandardMaterial({ color: 0xdfe6ee, metalness: 0.6, roughness: 0.4 })
36	  );
37	  ring.rotation.x = Math.PI / 2;
38	  ring.position.y = -0.03;
39	  g.add(glass, ring);
40	  return g;
41	}
42	
43	function buildLogbook() {
44	  const g = new THREE.Group();
45	  const book = new THREE.Mesh(
46	    new THREE.BoxGeometry(0.08, 0.02, 0.1),
47	    new THREE.MeshStandardMaterial({ color: 0x8a5a3a, roughness: 0.8 })
48	  );
49	  const page = new THREE.Mesh(
50	    new THREE.BoxGeometry(0.075, 0.005, 0.095),
51	    new THREE.MeshStandardMaterial({ color: 0xe8e0cf, roughness: 0.9 })
52	  );
53	  page.position.y = 0.012;
54	  page.rotation.y = 0.3;
55	  g.add(book, page);
56	  return g;
57	}
58	
59	function buildPanel() {
60	  const g = new THREE.Group();
61	  const body = new THREE.Mesh(
62	    new THREE.BoxGeometry(0.12, 0.015, 0.08),
63	    new THREE.MeshStandardMaterial({ color: 0x2a2f3a, metalness: 0.5, roughness: 0.4 })
64	  );
65	  const screen = new THREE.Mesh(
66	    new THREE.PlaneGeometry(0.09, 0.05),
67	    new THREE.MeshStandardMaterial({
68	      color: 0x0c2030, emissive: 0x123a4a, emissiveIntensity: 0.8, roughness: 0.3,
69	    })
70	  );
71	  screen.rotation.x = -Math.PI / 2;
72	  screen.position.y = 0.009;
73	  g.add(body, screen);
74	  return g;
75	}
76	
77	function buildBeacon() {
78	  const g = new THREE.Group();
79	  const base = new THREE.Mesh(
80	    new THREE.CylinderGeometry(0.02, 0.035, 0.1, 12),
81	    new THREE.MeshStandardMaterial({ color: 0x44484f, metalness: 0.7, roughness: 0.35 })
82	  );
83	  const light = new THREE.Mesh(
84	    new THREE.SphereGeometry(0.025, 16, 16),
85	    new THREE.MeshStandardMaterial({
86	      color: 0xffb86b, emissive: 0xffb86b, emissiveIntensity: 1.4,
87	    })
88	  );
89	  light.position.y = 0.07;
90	  g.add(base, light);
91	  g.userData.pulse = light;
92	  return g;
93	}
94	
95	// Exported so the island view can reuse the same little props on the ground.
96	export const BUILDERS = {
97	  helmet: buildHelmet,
98	  logbook: buildLogbook,
99	  panel: buildPanel,
100	  beacon: buildBeacon,
101	};
102	
103	// Catalog of fragments scattered on the planet. Each seeds a future
104	// context-recovery challenge mapped to a real `entire` command.
105	export const FRAGMENTS = [
106	  {
107	    kind: "helmet",
108	    lat: 28, lon: -52,
109	    title: "Abandoned EVA Helmet",
110	    body: "The visor is fogged from the inside. Its tiny logger still loops one phrase: a recap that started but never finished. Whoever wore this was trying to remember something — fast.",
111	    hint: "entire recap",
112	  },
113	  {
114	    kind: "logbook",
115	    lat: -14, lon: 122,
116	    title: "Torn Logbook Page",
117	    body: "Coordinates, half-erased by rain. Beneath the smudged ink a single checkpoint marker bleeds through — as if someone wanted a way back to this exact moment.",
118	    hint: "entire checkpoint",
119	  },
120	  {
121	    kind: "panel",
122	    lat: 52, lon: 18,
123	    title: "Cracked Nav Panel",
124	    body: "Diagnostics flatlined mid-write. The activity trail scrolls up the shattered glass and then simply… stops. The last legible line is a timestamp from the night of the crash.",
125	    hint: "entire activity",
126	  },
127	  {
128	    kind: "beacon",
129	    lat: -40, lon: -120,
130	    title: "Signal Beacon",
131	    body: "Still pulsing, somehow. It's been broadcasting the same dispatch into the dark for days — a summary of work no one is left to read.",
132	    hint: "entire dispatch",
133	  },
134	];
135	
136	// Convert lat/lon (degrees) to a point on a sphere of the given radius.
137	function latLonToVec3(lat, lon, radius) {
138	  const phi = (90 - lat) * (Math.PI / 180);
139	  const theta = (lon + 180) * (Math.PI / 180);
140	  return new THREE.Vector3(
141	    -radius * Math.sin(phi) * Math.cos(theta),
142	    radius * Math.cos(phi),
143	    radius * Math.sin(phi) * Math.sin(theta)
144	  );
145	}
146	
147	/**
148	 * Build debris anchors on the planet surface. Returns the group (to add to the
149	 * planet so they rotate together) and the list of pickable meshes for
150	 * raycasting, each carrying its fragment data in userData.
151	 */
152	export function createDebris(planetRadius) {
153	  const group = new THREE.Group();
154	  const pickables = [];
155	
156	  for (const frag of FRAGMENTS) {
157	    const pos = latLonToVec3(frag.lat, frag.lon, planetRadius);
158	    const anchor = new THREE.Group();
159	    anchor.position.copy(pos);
160	    // Orient so local +Y points away from the planet centre.
161	    anchor.quaternion.setFromUnitVectors(
162	      new THREE.Vector3(0, 1, 0),
163	      pos.clone().normalize()
164	    );
165	
166	    const model = BUILDERS[frag.kind]();
167	    model.position.y = 0.02;
168	
169	    // Halo to make it findable; doubles as the click target (big & flat).
170	    const halo = new THREE.Mesh(
171	      new THREE.PlaneGeometry(0.34, 0.34),
172	      new THREE.MeshBasicMaterial({
173	        map: haloTexture(),
174	        transparent: true,
175	        blending: THREE.AdditiveBlending,
176	        depthWrite: false,
177	        opacity: 0.9,
178	      })
179	    );
180	    halo.rotation.x = -Math.PI / 2;
181	    halo.position.y = 0.005;
182	
183	    anchor.add(halo, model);
184	    anchor.userData = { fragment: frag, halo, model, baseScale: 1 };
185	    group.add(anchor);
186	    pickables.push(anchor);
187	  }
188	
189	  return { group, pickables };
190	}
191

