/* Loader */
#loader {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 22px;
  background: #02040a;
  z-index: 50;
  transition: opacity 0.8s ease;
}

#loader.done {
  opacity: 0;
  pointer-events: none;
}

.loader-ring {
  width: 46px;
  height: 46px;
  border: 2px solid rgba(111, 227, 255, 0.2);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 0.9s linear infinite;
}

.loader-text {
  font-size: 12px;
  letter-spacing: 0.35em;
  opacity: 0.7;
}

@keyframes spin { to { transform: rotate(360deg); } }

.hidden { display: none; }

