295	  // How hard the sky is panicking right now: 0 = calm lavender, 1 = full crimson throb.
296	  function panicFactor() {
297	    if (failed) return 1;                         // hold the dread behind the fail screen
298	    if (!timerRunning || timeLeft > PANIC_TIME) return 0;
299	    let p = (PANIC_TIME - timeLeft) / PANIC_TIME; // 0 at PANIC_TIME → 1 at 0:00
