615	    a.iceY = ice.position.y;
616	    a.anchor.add(ice);
617	    a.ice = ice;
618	    teachOnce("committed",
619	      "Committed and frozen — locked in. Now Entire offers to link a checkpoint: press y to capture the session behind this commit.");
620	  }
621	  function confirmCheckpoint(yes) {
622	    const a = termTarget;
623	    if (!a || a.state !== "frozen") return;
624	    if (!yes) {
625	      flashTerminal("declined — without a checkpoint the ship can't track this commit. re-approach to link it.", false);
626	      closeTerminal(true);
627	      return;
628	    }
629	    checkpoint(a);
630	    if (allLinked()) {
631	      reviewMode = true;             // clock KEEPS running — the list is the finish line
632	      shipMeter?.classList.add("is-full");
633	      showTutorial("All banked! Now type `entire checkpoint list` before the clock hits 0:00 — hurry!", 0);
634	      renderTerminal();              // stay open → review step
635	    } else {
636	      closeTerminal(false);
637	    }
