639	  function checkpoint(a) {
640	    a.state = "checkpointed";
641	    a.id = genCheckpointId();
642	    const shipPct = 62 + Math.floor(Math.random() * 23); // 62–84%
643	
644	    if (a.ice) {
645	      a.ice.material.emissive.setHex(0x2a6c8a);
646	      a.ice.material.emissiveIntensity = 1.1;
647	      const core = new THREE.PointLight(0x8fe3ff, 6, 26, 2);
