668	  function onKeyDown(e) {
669	    if (!active) return;
670	
671	    // Landing briefing is up — Enter/Space begins the run, nothing else.
672	    if (!started) {
673	      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
674	      return;
