693	      if (step?.type === "confirm") {
694	        if (e.key === "y" || e.key === "Y") { confirmCheckpoint(true); e.preventDefault(); return; }
695	        if (e.key === "n" || e.key === "N") { confirmCheckpoint(false); e.preventDefault(); return; }
696	        e.preventDefault();
