712	    if (e.code === "KeyB") onExit?.();
713	  }
714	  fp.controls.addEventListener("lock", () => crosshair?.classList.remove("hidden"));
715	  fp.controls.addEventListener("unlock", () => crosshair?.classList.add("hidden"));
716	
717	  // ---------- HUD per-frame ----------
718	  function refreshHud() {
719	    if (!started || terminalOpen) {     // briefing up or terminal open → no walk HUD
720	      setPrompt(null);
721	      hideControls();
722	      hideActionBar();
723	      return;
724	    }
725	    setControls(fp.isLocked);
726	    hideActionBar();
727	    if (devLevel2) {
728	      setPrompt(fp.isLocked ? "Level 2 dev start — press B to return to orbit" : "Click to look around");
729	      return;
730	    }
731	    if (!fp.isLocked) { setPrompt("Click to look around"); return; }
732	    if (listShown) { setPrompt("Memory restored — press B to return to orbit"); return; }
733	    setPrompt("Find the surfacing memory");
734	  }
735	
736	  // ---------- per-frame ----------
737	  function update(dt, t) {
738	    fp.update(dt);
739	
740	    // Level countdown — one clock for the whole run.
741	    if (active && timerRunning && !failed) {
742	      timeLeft = Math.max(0, timeLeft - dt);
743	      updateClock();
744	      if (timeLeft <= 0) failLevel();
745	    }
746	    applyPanicSky();   // the sky reacts to the clock every frame
747	
748	    // Nearest memory within reach (ignoring height).
749	    let nearest = null, nd = Infinity;
750	    for (const a of artifacts) {
751	      const dx = camera.position.x - a.anchor.position.x;
752	      const dz = camera.position.z - a.anchor.position.z;
753	      const d = Math.hypot(dx, dz);
754	      if (d < nd) { nd = d; nearest = a; }
755	    }
756	    target = nd <= INTERACT_DIST ? nearest : null;
757	
758	    // Auto open/close the ship's terminal as you reach a memory.
759	    // (In review mode the terminal is driven manually, so leave it alone.)
760	    if (active && started && !reviewMode && !failed && !devLevel2) {
761	      if (dismissedMemory && target !== dismissedMemory) dismissedMemory = null;
762	      const canOpen = target && target.state !== "checkpointed" && target !== dismissedMemory;
763	      if (canOpen && !terminalOpen) openTerminal(target);
764	      else if (!canOpen && terminalOpen) closeTerminal(false);
765	    }
766	
767	    for (const a of artifacts) {
768	      // Melting away after a time-out — sink and fade, then disappear.
769	      if (a.melting) {
770	        a.meltT = Math.max(0, a.meltT - dt);
771	        const k = a.meltT / MELT_DUR;
772	        setModelOpacity(a.model, k);
773	        a.model.position.y -= dt * 2.4;
774	        if (a.ice) a.ice.material.opacity = 0.62 * k;
775	        a.beam.visible = false;
776	        a.glow.visible = false;
