778	      }
779	
780	      const encased = a.state === "frozen" || a.state === "checkpointed";
781	
782	      // Idle spin/bob until the memory is encased in ice.
783	      if (!encased) {
784	        a.model.rotation.y += dt * 0.6;
785	        a.model.position.y = 1.4 + Math.sin((t + a.bobOff) * 1.5) * 0.4;
786	        setModelOpacity(a.model, 1);
