788	
789	      // Beam + glow: bright while findable, gone once frozen.
790	      const lit = a.state === "dormant" || a.state === "recovered";
791	      let o = 0;
792	      if (a.state === "dormant") o = 0.4 + Math.sin(t * 2) * 0.12;
793	      else if (a.state === "recovered") o = 0.22;
794	      a.beam.material.opacity = o;
795	      a.beam.visible = o > 0.01;
