715	      if (!encased) {
716	        a.model.rotation.y += dt * 0.6;
717	        a.model.position.y = 1.4 + Math.sin((t + a.bobOff) * 1.5) * 0.4;
718	        setModelOpacity(a.model, 1);
719	      }
720	
721	      // Beam + glow: bright while findable, gone once frozen.
722	      const lit = a.state === "dormant" || a.state === "recovered";
723	      let o = 0;
724	      if (a.state === "dormant") o = 0.4 + Math.sin(t * 2) * 0.12;
725	      else if (a.state === "recovered") o = 0.22;
726	      a.beam.material.opacity = o;
727	      a.beam.visible = o > 0.01;
728	      a.glow.visible = lit;
729	    }
730	
731	    if (terminalOpen) renderTerminal(); // reflect fade-driven state changes
732	    if (active) refreshHud();
733	  }
734	
735	  // ---------- lifecycle ----------
736	  function enter() {
737	    active = true;
738	    fp.groundAt(0, terrain.radius * 0.75);
739	    camera.lookAt(0, terrain.heightAt(0, 0) + 6, 0);
740	    canvas.addEventListener("click", onCanvasClick);
741	    window.addEventListener("keydown", onKeyDown);
742	    islandHud?.classList.remove("hidden");
743	    islandHud?.classList.toggle("is-level2-dev", devLevel2);
744	    devLevelBadge?.classList.toggle("hidden", !devLevel2);
745	    fpShared?.classList.remove("hidden");
746	    setControls(false);
747	    crosshair?.classList.add("hidden");
748	    setPower();
749	    if (devLevel2) {
750	      seedLevel2DevState();
751	      fp.attach();
752	      showTutorial("Level 2 dev mode — Level 1 checkpoints are preloaded.", 0);
753	    } else if (!started) {          // fresh landing — read the briefing, then START
754	      showBriefing();
755	    } else if (listShown) {         // truly done — the list has been run
756	      fp.attach();
757	      timerRunning = false;
758	      showTutorial("Memory restored — press B to return to orbit.", 0);
759	    } else if (failed) {
760	      resetLevel();                 // came back after a wipe → fresh run
761	    } else {
762	      fp.attach();
763	      timerRunning = true;          // resume the level clock
764	      if (reviewMode) {             // resume the timed final review
765	        openTerminal(artifacts[0]); // termTarget unused in review; reopens the prompt
766	        showTutorial("Type `entire checkpoint list` before the clock hits 0:00!", 0);
767	      } else {
768	        showTutorial("Memories are surfacing — the clock's short. Bank all three before 0:00!", 6500);
769	      }
770	    }
771	    updateClock();
772	    applyPanicSky();   // start on the right sky (calm unless we resumed low on time)
773	  }
774	  function exit() {
775	    active = false;
776	    timerRunning = false;           // pause the clock while in orbit
777	    closeTerminal(false);
778	    fp.unlock();
779	    fp.detach();
780	    canvas.removeEventListener("click", onCanvasClick);
781	    window.removeEventListener("keydown", onKeyDown);
782	    setPrompt(null);
783	    hideControls();
784	    hideActionBar();
785	    tutorialEl?.classList.add("hidden");
786	    ckptCard?.classList.add("hidden");
787	    termEl?.classList.add("hidden");
788	    levelFail?.classList.add("hidden");
789	    briefingEl?.classList.add("hidden");
790	    islandHud?.classList.add("hidden");
791	    islandHud?.classList.remove("is-level2-dev");
792	    devLevelBadge?.classList.add("hidden");
793	    fpShared?.classList.add("hidden");
794	    crosshair?.classList.add("hidden");
795	  }
796	  function resize() {
797	    camera.aspect = window.innerWidth / window.innerHeight;
798	    camera.updateProjectionMatrix();
799	  }
800	
801	  return { scene, camera, update, enter, exit, resize };
