/* ---------- Level 2 HUD ("The Corruption") ---------- */

/* Corruption gauge — horizontal magenta bar where Level 1's clock sat */
#corrupt-meter {
  position: absolute;
  top: 78px;
  left: 32px;
  display: flex;
  align-items: center;
  gap: 11px;
  padding: 10px 16px;
  background: rgba(14, 5, 16, 0.78);
  border: 1px solid rgba(255, 43, 214, 0.4);
  border-radius: 9px;
  backdrop-filter: blur(8px);
}
.cm-label {
  font-size: 10.5px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: #ff8ad8;
  opacity: 0.95;
}
.cm-track {
  position: relative;
  width: 130px;
  height: 10px;
  border-radius: 6px;
  background: rgba(255, 43, 214, 0.14);
  border: 1px solid rgba(255, 43, 214, 0.22);
  overflow: hidden;
}
#corrupt-fill {
  position: absolute;
  inset: 0 auto 0 0;
  width: 0%;
  border-radius: 6px;
  background: linear-gradient(90deg, #7a1257, #ff2bd6);
  box-shadow: 0 0 12px rgba(255, 43, 214, 0.7);
  transition: width 0.4s linear;
}
#corrupt-pct {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 16px;
  font-weight: 700;
  min-width: 44px;
  text-align: right;
  color: var(--ink);
  font-variant-numeric: tabular-nums;
}
#corrupt-meter.is-high {
  border-color: rgba(255, 43, 214, 0.85);
  animation: cd-pulse 1s ease-in-out infinite;
}

/* Clue tracker — words gathered for the search */
#clue-tracker {
  position: absolute;
  top: 134px;
  left: 32px;
  display: flex;
  align-items: center;
  gap: 11px;
  padding: 8px 16px;
  background: rgba(6, 11, 22, 0.7);
  border: 1px solid rgba(255, 210, 122, 0.32);
  border-radius: 9px;
  backdrop-filter: blur(8px);
}
#clue-tracker .cm-label { color: var(--accent-warm); }
#clue-count {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 15px;
  font-weight: 700;
  color: var(--ink);
  font-variant-numeric: tabular-nums;
}

/* Clue card — what a frozen memory remembers */
#clue-card {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) scale(0.96);
  width: min(380px, 88vw);
  padding: 20px 22px;
  background: rgba(10, 8, 20, 0.92);
  border: 1px solid rgba(255, 210, 122, 0.45);
  border-radius: 10px;
  box-shadow: 0 18px 60px rgba(2, 4, 10, 0.6), 0 0 30px rgba(255, 210, 122, 0.16);
  backdrop-filter: blur(6px);
  opacity: 0;
  transition: opacity 0.3s ease, transform 0.3s cubic-bezier(0.22, 1, 0.36, 1);
}
#clue-card:not(.hidden) {
  opacity: 1;
  transform: translate(-50%, -50%) scale(1);
}
.qc-head {
  font-size: 11px;
  letter-spacing: 0.22em;
  color: var(--accent-warm);
}
.qc-title {
  margin: 10px 0 8px;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.02em;
}
.qc-body {
  font-size: 13px;
  line-height: 1.6;
  color: var(--ink);
  opacity: 0.85;
  margin-bottom: 14px;
}
.qc-keyrow {
  padding-top: 11px;
  border-top: 1px solid rgba(255, 210, 122, 0.2);
  font-size: 11.5px;
  color: rgba(232, 244, 255, 0.55);
}
.qc-keyrow span {
  color: var(--accent-warm);
  font-weight: 700;
}
.qc-foot {
  margin-top: 12px;
  font-size: 11px;
  letter-spacing: 0.06em;
  color: var(--ink);
  opacity: 0.6;
}

/* The good rewind landed */
#l2-win {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: min(440px, 88vw);
  padding: 28px 30px;
  text-align: center;
  background: rgba(8, 18, 16, 0.92);
  border: 1px solid rgba(92, 255, 176, 0.5);
  border-radius: 12px;
  box-shadow: 0 18px 60px rgba(2, 4, 10, 0.6), 0 0 40px rgba(92, 255, 176, 0.2);
  backdrop-filter: blur(6px);
}
.lw-title {
  font-size: 20px;
  letter-spacing: 0.22em;
  font-weight: 700;
  color: #7cffb0;
  margin-bottom: 10px;
}
.lw-sub {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 12px;
  line-height: 1.5;
  color: var(--accent);
  margin-bottom: 16px;
}
.lw-reveal {
  font-size: 12.5px;
  line-height: 1.6;
  color: var(--ink);
  opacity: 0.85;
  margin-bottom: 18px;
}
.lw-reveal code {
  font-family: ui-monospace, monospace;
  font-size: 11.5px;
  padding: 1px 5px;
  border-radius: 4px;
  background: rgba(111, 227, 255, 0.1);
  color: var(--accent);
}

/* Magenta flash when a rewind lands on a tainted checkpoint */
#glitch-flash {
  position: fixed;
  inset: 0;
  background: #ff2bd6;
  opacity: 0;
  pointer-events: none;
  z-index: 35;
}
#glitch-flash.show {
  animation: glitch-flash 0.5s steps(3, end) both;
}
@keyframes glitch-flash {
  0% { opacity: 0.45; }
  40% { opacity: 0.12; }
  70% { opacity: 0.3; }
  100% { opacity: 0; }
}

