const params = new URLSearchParams(location.search);
const requestedView = params.get("view");
const requestedLevel = params.get("level");
const devStartLevel = requestedView === "level2" || requestedLevel === "2" ? 2 : 1;

// ---------- views ----------
const planetView = createPlanetView(renderer, {
  onIslandClick: () => switchTo(islandView),
});
const islandView = createIslandView(renderer, {
  onExit: () => switchTo(planetView),
  devStartLevel,
});

// Default to the orbit view; ?view=island jumps to L1, while ?view=level2 or
// ?level=2 jumps to the Level 2 development staging point.
let current = requestedView === "island" || devStartLevel === 2
  ? islandView : planetView;
current.enter();

// ---------- fade transition ----------
const fade = document.getElementById("fade");
const hint = document.getElementById("hint");
let transitioning = false;
hint.classList.toggle("hidden", current !== planetView);

function switchTo(view) {
  if (transitioning || view === current) return;
  transitioning = true;
  fade.classList.add("show");
  setTimeout(() => {
    current.exit();
    current = view;
    current.enter();
    hint.classList.toggle("hidden", current !== planetView);
    fade.classList.remove("show");
    transitioning = false;
  }, 650); // match #fade CSS transition
}

// ---------- resize ----------
window.addEventListener("resize", () => {
  renderer.setSize(window.innerWidth, window.innerHeight);
  planetView.resize();
  islandView.resize();
});

// ---------- loop ----------
const clock = new THREE.Clock();
let firstFrame = true;

function animate() {
  const dt = Math.min(clock.getDelta(), 0.05); // clamp big tab-switch jumps
  const t = clock.elapsedTime;
  current.update(dt, t);
  renderer.render(current.scene, current.camera);

  if (firstFrame) {
    firstFrame = false;
    document.getElementById("loader").classList.add("done");
  }
  requestAnimationFrame(animate);
}
animate();

