input.content:
import { chromium } from "playwright";

const URL = "http://localhost:5174/?view=level2";
const shot = (page, name) => page.screenshot({ path: `/tmp/l2-${name}.png` });
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

const browser = await chromium.launch({
  headless: true,
  args: ["--autoplay-policy=no-user-gesture-required"],
});
const page = await browser.newPage({ viewport: { width: 1280, height: 800 } });
page.on("pageerror", (e) => console.log("PAGEERROR:", e.message));
page.on("console", (m) => { if (m.type() === "error") console.log("CONSOLE:", m.text()); });

await page.goto(URL);
await sleep(2500);

// 1. Briefing should be up
const briefingVisible = await page.evaluate(() =>
  !document.getElementById("l2-briefing").classList.contains("hidden"));
console.log("briefing visible:", briefingVisible);
console.log("briefing title:", await page.textContent("#l2-briefing .bf-title"));
await shot(page, "1-briefing");

// 2. Dismiss with Enter
await page.keyboard.press("Enter");
await sleep(500);
console.log("briefing dismissed:", await page.evaluate(() =>
  document.getElementById("l2-briefing").classList.contains("hidden")));
console.log("corrupt meter:", await page.textContent("#corrupt-pct"));
console.log("clue count:", await page.textContent("#clue-count"));

// 3. Click canvas → pointer lock
await page.click("#scene", { position: { x: 640, y: 400 } });
await sleep(600);
const locked = await page.evaluate(() => document.pointerLockElement !== null);
console.log("pointer locked:", locked);

const promptText = () => page.evaluate(() =>
  document.getElementById("fp-prompt").textContent);
const terminalOpen = () => page.evaluate(() =>
  !document.getElementById("terminal").classList.contains("hidden"));

console.log("prompt:", await promptText());

// 4. Walk forward toward the console (camera starts facing it)
await page.keyboard.down("ArrowUp");
let opened = false;
for (let i = 0; i < 30; i++) {
  await sleep(150);
  if (await terminalOpen()) { opened = true; break; }
}
await page.keyboard.up("ArrowUp");
console.log("terminal opened by walking:", opened);
await shot(page, "2-terminal");
console.log("term hint:", await page.textContent("#term-hint"));
console.log("term cta:", await page.textContent("#term-cta"));

// 5. Search before any clue — gating message
await page.keyboard.type('entire checkpoint search "course plot"');
await page.keyboard.press("Enter");
await sleep(300);
console.log("search (no clues) list:", await page.evaluate(() =>
  document.getElementById("term-list").innerText.replace(/\n/g, " | ")));
console.log("search msg:", await page.textContent("#term-msg"));
await shot(page, "3-search");

// 6. Explain the good candidate
await page.keyboard.type("entire checkpoint explain 8c21d4e7a90f");
await page.keyboard.press("Enter");
await sleep(300);
console.log("explain output:", await page.evaluate(() =>
  document.getElementById("term-list").innerText.replace(/\n/g, " | ")));
await shot(page, "4-explain");

// 7. Probe: bogus command + bogus explain id
await page.keyboard.type("entire checkpoint explain zzzz");
await page.keyboard.press("Enter");
await sleep(200);
console.log("bogus explain msg:", await page.textContent("#term-msg"));
await page.keyboard.type("git push --force");
await page.keyboard.press("Enter");
await sleep(200);
console.log("bogus cmd msg:", await page.textContent("#term-msg"));

// 8. Rewind browser
await page.keyboard.type("entire checkpoint rewind");
await page.keyboard.press("Enter");
await sleep(300);
console.log("browser list:", await page.evaluate(() =>
  document.getElementById("term-list").innerText.replace(/\n/g, " | ")));
await shot(page, "5-rewind-browser");

// 9. Probe: rewind to the DECOY first (newest first → index 0 is 04:15 tainted)
await page.keyboard.press("Enter");      // select top (tainted)
await sleep(200);
console.log("confirm line:", await page.textContent("#term-input"));
const pctBefore = await page.textContent("#corrupt-pct");
await page.keyboard.press("y");
await sleep(600);
console.log("decoy rewind msg:", await page.textContent("#term-msg"));
console.log("corruption surge:", pctBefore, "→", await page.textContent("#corrupt-pct"));
await shot(page, "6-decoy-softfail");

// 10. Rewind again to the GOOD checkpoint (index 2: 03:12)
await page.keyboard.type("entire checkpoint rewind");
await page.keyboard.press("Enter");
await sleep(300);
await page.keyboard.press("ArrowDown");
await page.keyboard.press("ArrowDown");
await sleep(200);
console.log("selected row:", await page.evaluate(() =>
  document.querySelector(".term-list-row.is-sel")?.innerText.replace(/\n/g, " ")));
await page.keyboard.press("Enter");
await sleep(200);
await page.keyboard.press("y");
await sleep(1500);
await shot(page, "7-restoring");
await sleep(4500);   // restore animation
const winVisible = await page.evaluate(() =>
  !document.getElementById("l2-win").classList.contains("hidden"));
console.log("win screen visible:", winVisible);
console.log("win sub:", await page.textContent("#l2-win-sub"));
await shot(page, "8-win");

// 11. B returns to orbit; pin should be corrupted
await page.keyboard.press("b");
await sleep(1500);
console.log("hint:", await page.textContent("#hint"));
console.log("pin corrupted:", await page.evaluate(() =>
  document.getElementById("island-pin").classList.contains("is-corrupted")));
await shot(page, "9-orbit");

await browser.close();
console.log("DONE");

