await page.keyboard.press("Enter");
await sleep(200);
console.log("bogus explain msg:", await page.textContent("#term-msg"));
await page.keyboard.type("git push --force");
await page.keyboard.press("Enter");
await sleep(200);
console.log("bogus cmd msg:", await page.textContent("#term-msg"));

// 8. Rewind browser
await page.keyboard.type("entire checkpoint rewind");
await page.keyboard.press("Enter");
await sleep(300);
console.log("browser list:", await page.evaluate(() =>
  document.getElementById("term-list").innerText.replace(/\n/g, " | ")));
await shot(page, "5-rewind-browser");

// 9. Probe: rewind to the DECOY first (newest first → index 0 is 04:15 tainted)
await page.keyboard.press("Enter");      // select top (tainted)
await sleep(200);
console.log("confirm line:", await page.textContent("#term-input"));
