await page.keyboard.press("Enter");
await sleep(200);
await page.keyboard.press("y");
await sleep(1500);
await shot(page, "7-restoring");
await sleep(4500);   // restore animation
const winVisible = await page.evaluate(() =>
  !document.getElementById("l2-win").classList.contains("hidden"));
console.log("win screen visible:", winVisible);
console.log("win sub:", await page.textContent("#l2-win-sub"));
await shot(page, "8-win");

// 11. B returns to orbit; pin should be corrupted
await page.keyboard.press("b");
await sleep(1500);
console.log("hint:", await page.textContent("#hint"));
console.log("pin corrupted:", await page.evaluate(() =>
  document.getElementById("island-pin").classList.contains("is-corrupted")));
await shot(page, "9-orbit");

await browser.close();
console.log("DONE");

