7	// The walkable island level — LEVEL 1 ("First Memories").
8	//
9	// A Diner-Dash-style loop, one memory at a time, driven by the REAL workflow
10	// typed into the ship's terminal:
11	//   walk up → terminal opens → `git add` (stage) → `git commit` (freeze in ice)
12	//   → Entire offers to link a checkpoint → press y → ship memory restores.
13	// When every memory is linked → run `entire checkpoint list` to review them all.
14	//
15	// PRESSURE: a single level countdown runs the whole time. Bank every memory
16	// before it hits zero, or the un-banked memories melt away and the run fails
17	// (press R to retry). One clock for the whole level — not per-memory.
18	//
19	// Teaching: a commit just freezes the change; linking a CHECKPOINT (the y/n
20	// offer Entire makes after a commit) is what restores it to the ship's memory.
21	
22	const INTERACT_DIST = 8;    // how close (XZ) to open a memory's terminal
23	const TOTAL_TIME = 45;      // seconds to recover & bank EVERY memory (tunable — scary-tight)
24	const MELT_DUR = 1.8;       // seconds the lost memories take to melt away
25	const LOW_TIME = 22;        // clock turns urgent (red, pulsing) under this many seconds
26	const CRIT_TIME = 8;        // clock goes CRITICAL (fast pulse) under this many seconds
27	const PANIC_TIME = 22;      // the SKY starts shifting toward panic-red under this many seconds
28	const MEMORY_COUNT = 3;     // calm tutorial: three memories
29	const BEAM_COLOR = 0xffd27a;
30	
31	// Sky panic palette — the whole world reddens as the clock runs out.
32	const SKY_CALM  = new THREE.Color(0x2a2350);  // lavender dusk (the resting sky/fog)
33	const SKY_PANIC = new THREE.Color(0x6e0f16);  // angry crimson
34	const FOG_PANIC = new THREE.Color(0x4a0a0e);  // deep blood fog closing in
35	const DOME_CALM = new THREE.Color(0x3a3168);
36	const DOME_PANIC = new THREE.Color(0x7a141c);
37	const SUN_CALM  = new THREE.Color(0xfff1dc);  // warm sun
38	const SUN_PANIC = new THREE.Color(0xff5a3c);  // hot red alarm light
39	
40	// Where each memory surfaces on the island (world XZ).
41	const PLACEMENTS = [
42	  { x: -34, z: -28 },
43	  { x: 40, z: -18 },
44	  { x: 28, z: 38 },
45	  { x: -30, z: 36 },
46	];
47	const DEV_LEVEL2_CHECKPOINTS = ["31f0cafe4d12", "7e11a2b09c44", "b0a7ded51a6e"];
48	
