595	  // ---------- input ----------
596	  function onCanvasClick() {
597	    if (!started) return;                 // briefing up — ignore world clicks
598	    if (active && !fp.isLocked) fp.lock();
599	  }
600	  function onKeyDown(e) {
601	    if (!active) return;
602	
603	    // Landing briefing is up — Enter/Space begins the run, nothing else.
604	    if (!started) {
605	      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
606	      return;
607	    }
608	
609	    // The run failed — only R (retry) does anything.
610	    if (failed) {
611	      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
612	      return;
613	    }
614	
615	    // While the terminal is open, all keys feed it.
616	    if (terminalOpen) {
617	      if (e.code === "Escape") {
618	        // No bailing on the final review — the clock is still ticking.
619	        if (reviewMode && !listShown) { e.preventDefault(); return; }
620	        closeTerminal(true); e.preventDefault(); return;
621	      }
622	      if (reviewMode && listShown) { e.preventDefault(); return; } // only Esc closes the list
623	
624	      const step = currentStep();
625	      if (step?.type === "confirm") {
626	        if (e.key === "y" || e.key === "Y") { confirmCheckpoint(true); e.preventDefault(); return; }
627	        if (e.key === "n" || e.key === "N") { confirmCheckpoint(false); e.preventDefault(); return; }
628	        e.preventDefault();
629	        return;
630	      }
631	      // command mode
632	      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
633	      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
634	      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
635	        buffer += e.key;
636	        renderTerminal();
637	        e.preventDefault();
638	      }
639	      return;
640	    }
641	
642	    // Walking around (terminal closed).
643	    if (e.code === "Escape" && fp.isLocked) fp.unlock();
644	    if (e.code === "KeyB") onExit?.();
645	  }
646	  fp.controls.addEventListener("lock", () => crosshair?.classList.remove("hidden"));
647	  fp.controls.addEventListener("unlock", () => crosshair?.classList.add("hidden"));
648	
649	  // ---------- HUD per-frame ----------
650	  function refreshHud() {
651	    if (!started || terminalOpen) {     // briefing up or terminal open → no walk HUD
652	      setPrompt(null);
653	      hideControls();
654	      hideActionBar();
655	      return;
656	    }
657	    setControls(fp.isLocked);
658	    hideActionBar();
659	    if (devLevel2) {
660	      setPrompt(fp.isLocked ? "Level 2 dev start — press B to return to orbit" : "Click to look around");
661	      return;
662	    }
663	    if (!fp.isLocked) { setPrompt("Click to look around"); return; }
664	    if (listShown) { setPrompt("Memory restored — press B to return to orbit"); return; }
665	    setPrompt("Find the surfacing memory");
666	  }
667	
668	  // ---------- per-frame ----------
669	  function update(dt, t) {
670	    fp.update(dt);
671	
672	    // Level countdown — one clock for the whole run.
673	    if (active && timerRunning && !failed) {
674	      timeLeft = Math.max(0, timeLeft - dt);
675	      updateClock();
676	      if (timeLeft <= 0) failLevel();
677	    }
678	    applyPanicSky();   // the sky reacts to the clock every frame
679	
680	    // Nearest memory within reach (ignoring height).
681	    let nearest = null, nd = Infinity;
682	    for (const a of artifacts) {
683	      const dx = camera.position.x - a.anchor.position.x;
684	      const dz = camera.position.z - a.anchor.position.z;
685	      const d = Math.hypot(dx, dz);
686	      if (d < nd) { nd = d; nearest = a; }
687	    }
688	    target = nd <= INTERACT_DIST ? nearest : null;
689	
690	    // Auto open/close the ship's terminal as you reach a memory.
691	    // (In review mode the terminal is driven manually, so leave it alone.)
692	    if (active && started && !reviewMode && !failed && !devLevel2) {
693	      if (dismissedMemory && target !== dismissedMemory) dismissedMemory = null;
694	      const canOpen = target && target.state !== "checkpointed" && target !== dismissedMemory;
695	      if (canOpen && !terminalOpen) openTerminal(target);
696	      else if (!canOpen && terminalOpen) closeTerminal(false);
697	    }
698	
699	    for (const a of artifacts) {
700	      // Melting away after a time-out — sink and fade, then disappear.
701	      if (a.melting) {
702	        a.meltT = Math.max(0, a.meltT - dt);
703	        const k = a.meltT / MELT_DUR;
704	        setModelOpacity(a.model, k);
705	        a.model.position.y -= dt * 2.4;
706	        if (a.ice) a.ice.material.opacity = 0.62 * k;
707	        a.beam.visible = false;
708	        a.glow.visible = false;
709	        continue;
710	      }
711	
712	      const encased = a.state === "frozen" || a.state === "checkpointed";
713	
714	      // Idle spin/bob until the memory is encased in ice.
715	      if (!encased) {
716	        a.model.rotation.y += dt * 0.6;
717	        a.model.position.y = 1.4 + Math.sin((t + a.bobOff) * 1.5) * 0.4;
718	        setModelOpacity(a.model, 1);
719	      }
720	
721	      // Beam + glow: bright while findable, gone once frozen.
722	      const lit = a.state === "dormant" || a.state === "recovered";
723	      let o = 0;
724	      if (a.state === "dormant") o = 0.4 + Math.sin(t * 2) * 0.12;
725	      else if (a.state === "recovered") o = 0.22;
726	      a.beam.material.opacity = o;
727	      a.beam.visible = o > 0.01;
728	      a.glow.visible = lit;
729	    }
730	
731	    if (terminalOpen) renderTerminal(); // reflect fade-driven state changes
732	    if (active) refreshHud();
733	  }
734	
735	  // ---------- lifecycle ----------
736	  function enter() {
737	    active = true;
738	    fp.groundAt(0, terrain.radius * 0.75);
739	    camera.lookAt(0, terrain.heightAt(0, 0) + 6, 0);
740	    canvas.addEventListener("click", onCanvasClick);
741	    window.addEventListener("keydown", onKeyDown);
742	    islandHud?.classList.remove("hidden");
743	    islandHud?.classList.toggle("is-level2-dev", devLevel2);
744	    devLevelBadge?.classList.toggle("hidden", !devLevel2);
745	    fpShared?.classList.remove("hidden");
746	    setControls(false);
747	    crosshair?.classList.add("hidden");
748	    setPower();
749	    if (devLevel2) {
750	      seedLevel2DevState();
751	      fp.attach();
752	      showTutorial("Level 2 dev mode — Level 1 checkpoints are preloaded.", 0);
753	    } else if (!started) {          // fresh landing — read the briefing, then START
754	      showBriefing();
755	    } else if (listShown) {         // truly done — the list has been run
756	      fp.attach();
757	      timerRunning = false;
758	      showTutorial("Memory restored — press B to return to orbit.", 0);
759	    } else if (failed) {
760	      resetLevel();                 // came back after a wipe → fresh run
761	    } else {
762	      fp.attach();
763	      timerRunning = true;          // resume the level clock
764	      if (reviewMode) {             // resume the timed final review
765	        openTerminal(artifacts[0]); // termTarget unused in review; reopens the prompt
766	        showTutorial("Type `entire checkpoint list` before the clock hits 0:00!", 0);
767	      } else {
768	        showTutorial("Memories are surfacing — the clock's short. Bank all three before 0:00!", 6500);
769	      }
770	    }
771	    updateClock();
772	    applyPanicSky();   // start on the right sky (calm unless we resumed low on time)
773	  }
774	  function exit() {
775	    active = false;
776	    timerRunning = false;           // pause the clock while in orbit
777	    closeTerminal(false);
778	    fp.unlock();
779	    fp.detach();
780	    canvas.removeEventListener("click", onCanvasClick);
781	    window.removeEventListener("keydown", onKeyDown);
782	    setPrompt(null);
783	    hideControls();
784	    hideActionBar();
785	    tutorialEl?.classList.add("hidden");
786	    ckptCard?.classList.add("hidden");
787	    termEl?.classList.add("hidden");
788	    levelFail?.classList.add("hidden");
789	    briefingEl?.classList.add("hidden");
790	    islandHud?.classList.add("hidden");
791	    islandHud?.classList.remove("is-level2-dev");
792	    devLevelBadge?.classList.add("hidden");
793	    fpShared?.classList.add("hidden");
794	    crosshair?.classList.add("hidden");
795	  }
796	  function resize() {
797	    camera.aspect = window.innerWidth / window.innerHeight;
798	    camera.updateProjectionMatrix();
799	  }
800	
801	  return { scene, camera, update, enter, exit, resize };
802	}
