file.content:
:root {
  --accent: #6fe3ff;
  --accent-warm: #ffb86b;
  --ink: #e8f4ff;
  --panel-bg: rgba(8, 14, 26, 0.82);
  --pin-shell: #171126;
  --pin-rim: rgba(255, 244, 232, 0.96);
  --pin-core: #d79e3a;
  --pin-shadow: rgba(2, 4, 10, 0.72);
}

* { margin: 0; padding: 0; box-sizing: border-box; }

html, body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  background: #02040a;
  color: var(--ink);
  font-family: "SF Mono", "JetBrains Mono", ui-monospace, Menlo, monospace;
  cursor: default;
}

#scene {
  position: fixed;
  inset: 0;
  display: block;
  width: 100%;
  height: 100%;
}

#ui {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 10;
}

#hud {
  position: absolute;
  top: 28px;
  left: 32px;
}

.hud-title {
  font-size: 26px;
  letter-spacing: 0.42em;
  font-weight: 600;
  text-shadow: 0 0 18px rgba(111, 227, 255, 0.55);
}

#hint {
  position: absolute;
  bottom: 26px;
  left: 50%;
  transform: translateX(-50%);
  font-size: 12px;
  letter-spacing: 0.12em;
  opacity: 0.55;
  white-space: nowrap;
}

/* Background music controls */
#audio-panel {
  position: absolute;
  top: 28px;
  right: 32px;
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  background: rgba(8, 14, 26, 0.58);
  border: 1px solid rgba(255, 244, 232, 0.18);
  border-radius: 6px;
  box-shadow: 0 12px 36px rgba(2, 4, 10, 0.34);
  backdrop-filter: blur(10px);
  pointer-events: auto;
}

.audio-mark {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 30px;
  height: 30px;
  color: rgba(255, 210, 122, 0.84);
}

.icon-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 30px;
  height: 30px;
  border: 1px solid rgba(255, 244, 232, 0.22);
  border-radius: 50%;
  background: rgba(255, 244, 232, 0.08);
  color: var(--ink);
  cursor: pointer;
  transition: background 0.18s ease, border-color 0.18s ease, transform 0.18s ease;
}

.icon-button:hover,
.icon-button:focus-visible {
  background: rgba(255, 184, 107, 0.16);
  border-color: rgba(255, 210, 122, 0.55);
  outline: none;
  transform: translateY(-1px);
}

#audio-panel.is-awaiting-start #audio-toggle {
  border-color: rgba(255, 210, 122, 0.7);
  animation: audio-start-pulse 1.6s ease-in-out infinite;
}

.icon {
  width: 15px;
  height: 15px;
  display: block;
  fill: currentColor;
}

.icon-pause,
#audio-toggle.is-playing .icon-play {
  display: none;
}

#audio-toggle.is-playing .icon-pause {
  display: block;
}

.icon-speaker .mute-mark {
  fill: none;
  stroke: currentColor;
  stroke-width: 1.8;
  stroke-linecap: round;
  opacity: 0;
}

#audio-mute.is-muted .mute-mark {
  opacity: 1;
}

#audio-volume {
  width: 92px;
  accent-color: var(--accent-warm);
  cursor: pointer;
}

#audio-volume:focus-visible {
  outline: 1px solid rgba(255, 210, 122, 0.75);
  outline-offset: 3px;
}

@keyframes audio-start-pulse {
  0%, 100% {
    box-shadow: 0 0 0 rgba(255, 184, 107, 0);
  }
  50% {
    box-shadow: 0 0 14px rgba(255, 184, 107, 0.42);
  }
}

/* ---------- Island level-1 HUD ---------- */

#dev-level-badge {
  position: absolute;
  top: 78px;
  left: 32px;
  display: none;
  align-items: baseline;
  gap: 10px;
  padding: 8px 12px;
  background: rgba(6, 11, 22, 0.78);
  border: 1px solid rgba(255, 184, 107, 0.45);
  border-radius: 8px;
  color: var(--ink);
  backdrop-filter: blur(8px);
  box-shadow: 0 0 24px rgba(255, 184, 107, 0.12);
}
#dev-level-badge:not(.hidden) {
  display: flex;
}
#dev-level-badge span {
  font-size: 10px;
  letter-spacing: 0.22em;
  color: var(--accent-warm);
  opacity: 0.9;
}
#dev-level-badge strong {
  font-size: 17px;
  letter-spacing: 0.08em;
}
#island-hud.is-level2-dev #countdown,
#island-hud.is-level2-dev #ship-meter {
  display: none;
}

/* Ship memory gauge — the level goal; only checkpoints fill it. A thick
   VERTICAL bar under the clock that fills bottom-up and shifts colour as the
   ship's memory is restored (warning amber → cyan → restored aqua-green). */
#ship-meter {
  position: absolute;
  top: 136px;
  left: 32px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  padding: 12px 14px;
  background: rgba(6, 11, 22, 0.7);
  border: 1px solid rgba(111, 227, 255, 0.32);
  border-radius: 12px;
  backdrop-filter: blur(8px);
}

.meter-label {
  font-size: 9.5px;
  letter-spacing: 0.18em;
  font-weight: 700;
  color: var(--accent);
  opacity: 0.95;
  white-space: nowrap;
}

.meter-track {
  position: relative;
  width: 22px;
  height: 150px;
  border-radius: 11px;
  background: rgba(111, 227, 255, 0.12);
  border: 1px solid rgba(111, 227, 255, 0.18);
  overflow: hidden;
}

#ship-meter-fill {
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 0%;
  border-radius: 11px;
  background: rgba(111, 227, 255, 0.4);
  transition: height 0.6s cubic-bezier(0.22, 1, 0.36, 1),
              background 0.5s ease, box-shadow 0.5s ease;
}
/* colour climbs with the fill */
#ship-meter.lvl-low #ship-meter-fill {
  background: linear-gradient(180deg, #ffc46b, #ff8a3c);
  box-shadow: 0 0 14px rgba(255, 150, 80, 0.7);
}
#ship-meter.lvl-mid #ship-meter-fill {
  background: linear-gradient(180deg, #9af0ff, #3aa6c8);
  box-shadow: 0 0 16px rgba(111, 227, 255, 0.8);
}
#ship-meter.lvl-high #ship-meter-fill {
  background: linear-gradient(180deg, #bfffe0, #5cffb0);
  box-shadow: 0 0 22px rgba(92, 255, 176, 0.95);
}

#ship-meter.is-full { border-color: rgba(92, 255, 176, 0.6); }
#ship-meter.is-full #ship-meter-fill { animation: meter-glow 1.8s ease-in-out infinite; }

#ship-meter-pct {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 15px;
  font-weight: 700;
  letter-spacing: 0.02em;
  text-align: center;
  color: var(--ink);
  opacity: 0.95;
  font-variant-numeric: tabular-nums;
}

@keyframes meter-glow {
  0%, 100% { filter: brightness(1); }
  50% { filter: brightness(1.4); }
}

/* Level countdown clock (top-left, under the PLANETFALL title) */
#countdown {
  position: absolute;
  top: 78px;
  left: 32px;
  display: flex;
  align-items: center;
  gap: 11px;
  padding: 8px 16px;
  background: rgba(6, 11, 22, 0.78);
  border: 1px solid rgba(111, 227, 255, 0.4);
  border-radius: 9px;
  backdrop-filter: blur(8px);
  transition: border-color 0.3s ease, background 0.3s ease;
}

.cd-label {
  font-size: 10.5px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: var(--accent);
  opacity: 0.95;
}

#countdown-time {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 27px;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: var(--ink);
  min-width: 66px;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

/* Urgent state — the clock is running low */
#countdown.is-low {
  border-color: rgba(255, 90, 90, 0.7);
  background: rgba(40, 10, 12, 0.6);
  animation: cd-pulse 1s ease-in-out infinite;
}
#countdown.is-low .cd-label { color: #ff7a6b; }
#countdown.is-low #countdown-time { color: #ff8a78; }

@keyframes cd-pulse {
  0%, 100% { box-shadow: 0 0 0 rgba(255, 90, 90, 0); }
  50% { box-shadow: 0 0 18px rgba(255, 90, 90, 0.55); }
}

/* Critical state — under a few seconds, the clock goes frantic */
#countdown.is-critical {
  border-color: rgba(255, 60, 60, 0.95);
  background: rgba(60, 8, 10, 0.72);
  animation: cd-panic 0.5s steps(2, end) infinite;
}
#countdown.is-critical .cd-label { color: #ff4d4d; }
#countdown.is-critical #countdown-time {
  color: #ff5a4d;
  text-shadow: 0 0 12px rgba(255, 70, 60, 0.9);
}

@keyframes cd-panic {
  0% { box-shadow: 0 0 22px rgba(255, 50, 50, 0.8); transform: translateX(-1px); }
  100% { box-shadow: 0 0 8px rgba(255, 50, 50, 0.4); transform: translateX(1px); }
}

/* Time-out fail screen */
/* ---------- landing briefing modal ---------- */
#briefing,
#l2-briefing {
  position: absolute;
  inset: 0;
  z-index: 30;
  pointer-events: auto;     /* #ui is pointer-events:none — re-enable for the modal */
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px;
  background: radial-gradient(ellipse at 50% 30%, rgba(20, 16, 44, 0.62), rgba(2, 4, 10, 0.86));
  backdrop-filter: blur(7px);
  animation: bf-fade 0.5s ease both;
}
#briefing.hidden,
#l2-briefing.hidden { display: none; }

@keyframes bf-fade {
  from { opacity: 0; }
  to { opacity: 1; }
}

.bf-card {
  width: min(540px, 92vw);
  max-height: 88vh;
  overflow-y: auto;
  padding: 30px 34px 26px;
  text-align: left;
  background: var(--panel-bg);
  border: 1px solid rgba(111, 227, 255, 0.28);
  border-radius: 16px;
  box-shadow: 0 26px 80px rgba(2, 4, 10, 0.7), 0 0 50px rgba(111, 227, 255, 0.12);
  animation: bf-rise 0.55s cubic-bezier(0.16, 1, 0.3, 1) both;
}

@keyframes bf-rise {
  from { opacity: 0; transform: translateY(14px) scale(0.98); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}

.bf-tag {
  font-size: 11px;
  letter-spacing: 0.26em;
  color: var(--accent);
  opacity: 0.85;
  margin-bottom: 8px;
}
.bf-title {
  font-size: 28px;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: var(--ink);
  margin-bottom: 14px;
}
.bf-story {
  font-size: 13.5px;
  line-height: 1.65;
  color: var(--ink);
  opacity: 0.82;
  margin-bottom: 20px;
}
.bf-mission {
  border-top: 1px solid rgba(111, 227, 255, 0.16);
  border-bottom: 1px solid rgba(111, 227, 255, 0.16);
  padding: 16px 0;
  margin-bottom: 18px;
}
.bf-mission-head {
  font-size: 11px;
  letter-spacing: 0.22em;
  color: var(--accent-warm);
  margin-bottom: 12px;
}
.bf-steps {
  list-style: none;
  counter-reset: bf;
  display: grid;
  gap: 11px;
}
.bf-steps li {
  counter-increment: bf;
  position: relative;
  padding-left: 34px;
  font-size: 13px;
  line-height: 1.5;
  color: var(--ink);
  opacity: 0.9;
}
.bf-steps li::before {
  content: counter(bf);
  position: absolute;
  left: 0;
  top: -1px;
  width: 22px;
  height: 22px;
  display: grid;
  place-items: center;
  font-size: 11.5px;
  font-weight: 700;
  color: var(--accent);
  border: 1px solid rgba(111, 227, 255, 0.4);
  border-radius: 50%;
}
.bf-steps code {
  font-family: ui-monospace, monospace;
  font-size: 12px;
  padding: 1px 6px;
  border-radius: 4px;
  background: rgba(111, 227, 255, 0.1);
  color: var(--accent);
}
.bf-steps strong { color: var(--ink); font-weight: 700; }
.bf-controls {
  margin-bottom: 18px;
}
.bf-ctrl-grid {
  display: grid;
  gap: 10px;
}
.bf-ctrl {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12.5px;
  color: var(--ink);
  opacity: 0.9;
}
.bf-keys {
  display: inline-flex;
  gap: 3px;
}
.bf-keys .bf-key { margin: 0; }
.bf-dim { opacity: 0.55; }

.bf-warn {
  font-size: 12.5px;
  line-height: 1.5;
  color: #ff8a78;
  opacity: 0.92;
  margin-bottom: 22px;
}
#briefing-start,
#l2-briefing-start {
  display: block;
  width: 100%;
  padding: 13px 20px;
  font-family: inherit;
  font-size: 14px;
  font-weight: 700;
  letter-spacing: 0.16em;
  color: #04121a;
  cursor: pointer;
  background: linear-gradient(90deg, #3aa6c8, var(--accent));
  border: none;
  border-radius: 10px;
  box-shadow: 0 0 26px rgba(111, 227, 255, 0.3);
  transition: transform 0.12s ease, box-shadow 0.2s ease;
}
#briefing-start:hover,
#l2-briefing-start:hover {
  transform: translateY(-1px);
  box-shadow: 0 0 36px rgba(111, 227, 255, 0.5);
}
#briefing-start:active,
#l2-briefing-start:active { transform: translateY(0); }
.bf-hint {
  margin-top: 12px;
  text-align: center;
  font-size: 12px;
  letter-spacing: 0.05em;
  color: var(--ink);
  opacity: 0.6;
}
.bf-key {
  display: inline-block;
  padding: 2px 7px;
  margin: 0 2px;
  border: 1px solid rgba(255, 244, 232, 0.45);
  border-radius: 4px;
  font-family: ui-monospace, monospace;
  font-weight: 600;
  color: var(--ink);
}

#level-fail,
#l2-fail {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: min(380px, 86vw);
  padding: 26px 28px;
  text-align: center;
  background: rgba(20, 8, 12, 0.9);
  border: 1px solid rgba(255, 90, 90, 0.5);
  border-radius: 12px;
  box-shadow: 0 18px 60px rgba(2, 4, 10, 0.6), 0 0 36px rgba(255, 90, 90, 0.2);
  backdrop-filter: blur(6px);
}

.lf-title {
  font-size: 20px;
  letter-spacing: 0.22em;
  font-weight: 700;
  color: #ff8a78;
  margin-bottom: 10px;
}
.lf-sub {
  font-size: 13px;
  line-height: 1.5;
  color: var(--ink);
  opacity: 0.85;
  margin-bottom: 18px;
}
.lf-hint {
  font-size: 12.5px;
  letter-spacing: 0.06em;
  color: var(--ink);
  opacity: 0.75;
}
.lf-key {
  display: inline-block;
  min-width: 20px;
  padding: 2px 7px;
  margin: 0 2px;
  border: 1px solid rgba(255, 244, 232, 0.45);
  border-radius: 4px;
  font-family: ui-monospace, monospace;
  font-weight: 600;
  color: var(--ink);
}

/* ---------- Level 2 HUD ("The Corruption") ---------- */

/* Corruption gauge — horizontal magenta bar where Level 1's clock sat */
#corrupt-meter {
  position: absolute;
  top: 78px;
  left: 32px;
  display: flex;
  align-items: center;
  gap: 11px;
  padding: 10px 16px;
  background: rgba(14, 5, 16, 0.78);
  border: 1px solid rgba(255, 43, 214, 0.4);
  border-radius: 9px;
  backdrop-filter: blur(8px);
}
.cm-label {
  font-size: 10.5px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: #ff8ad8;
  opacity: 0.95;
}
.cm-track {
  position: relative;
  width: 130px;
  height: 10px;
  border-radius: 6px;
  background: rgba(255, 43, 214, 0.14);
  border: 1px solid rgba(255, 43, 214, 0.22);
  overflow: hidden;
}
#corrupt-fill {
  position: absolute;
  inset: 0 auto 0 0;
  width: 0%;
  border-radius: 6px;
  background: linear-gradient(90deg, #7a1257, #ff2bd6);
  box-shadow: 0 0 12px rgba(255, 43, 214, 0.7);
  transition: width 0.4s linear;
}
#corrupt-pct {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 16px;
  font-weight: 700;
  min-width: 44px;
  text-align: right;
  color: var(--ink);
  font-variant-numeric: tabular-nums;
}
#corrupt-meter.is-high {
  border-color: rgba(255, 43, 214, 0.85);
  animation: cd-pulse 1s ease-in-out infinite;
}

/* Clue tracker — words gathered for the search */
#clue-tracker {
  position: absolute;
  top: 134px;
  left: 32px;
  display: flex;
  align-items: center;
  gap: 11px;
  padding: 8px 16px;
  background: rgba(6, 11, 22, 0.7);
  border: 1px solid rgba(255, 210, 122, 0.32);
  border-radius: 9px;
  backdrop-filter: blur(8px);
}
#clue-tracker .cm-label { color: var(--accent-warm); }
#clue-count {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 15px;
  font-weight: 700;
  color: var(--ink);
  font-variant-numeric: tabular-nums;
}

/* Clue card — what a frozen memory remembers */
#clue-card {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) scale(0.96);
  width: min(380px, 88vw);
  padding: 20px 22px;
  background: rgba(10, 8, 20, 0.92);
  border: 1px solid rgba(255, 210, 122, 0.45);
  border-radius: 10px;
  box-shadow: 0 18px 60px rgba(2, 4, 10, 0.6), 0 0 30px rgba(255, 210, 122, 0.16);
  backdrop-filter: blur(6px);
  opacity: 0;
  transition: opacity 0.3s ease, transform 0.3s cubic-bezier(0.22, 1, 0.36, 1);
}
#clue-card:not(.hidden) {
  opacity: 1;
  transform: translate(-50%, -50%) scale(1);
}
.qc-head {
  font-size: 11px;
  letter-spacing: 0.22em;
  color: var(--accent-warm);
}
.qc-title {
  margin: 10px 0 8px;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.02em;
}
.qc-body {
  font-size: 13px;
  line-height: 1.6;
  color: var(--ink);
  opacity: 0.85;
  margin-bottom: 14px;
}
.qc-keyrow {
  padding-top: 11px;
  border-top: 1px solid rgba(255, 210, 122, 0.2);
  font-size: 11.5px;
  color: rgba(232, 244, 255, 0.55);
}
.qc-keyrow span {
  color: var(--accent-warm);
  font-weight: 700;
}
.qc-foot {
  margin-top: 12px;
  font-size: 11px;
  letter-spacing: 0.06em;
  color: var(--ink);
  opacity: 0.6;
}

/* The good rewind landed */
#l2-win {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: min(440px, 88vw);
  padding: 28px 30px;
  text-align: center;
  background: rgba(8, 18, 16, 0.92);
  border: 1px solid rgba(92, 255, 176, 0.5);
  border-radius: 12px;
  box-shadow: 0 18px 60px rgba(2, 4, 10, 0.6), 0 0 40px rgba(92, 255, 176, 0.2);
  backdrop-filter: blur(6px);
}
.lw-title {
  font-size: 20px;
  letter-spacing: 0.22em;
  font-weight: 700;
  color: #7cffb0;
  margin-bottom: 10px;
}
.lw-sub {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 12px;
  line-height: 1.5;
  color: var(--accent);
  margin-bottom: 16px;
}
.lw-reveal {
  font-size: 12.5px;
  line-height: 1.6;
  color: var(--ink);
  opacity: 0.85;
  margin-bottom: 18px;
}
.lw-reveal code {
  font-family: ui-monospace, monospace;
  font-size: 11.5px;
  padding: 1px 5px;
  border-radius: 4px;
  background: rgba(111, 227, 255, 0.1);
  color: var(--accent);
}

/* Magenta flash when a rewind lands on a tainted checkpoint */
#glitch-flash {
  position: fixed;
  inset: 0;
  background: #ff2bd6;
  opacity: 0;
  pointer-events: none;
  z-index: 35;
}
#glitch-flash.show {
  animation: glitch-flash 0.5s steps(3, end) both;
}
@keyframes glitch-flash {
  0% { opacity: 0.45; }
  40% { opacity: 0.12; }
  70% { opacity: 0.3; }
  100% { opacity: 0; }
}

/* Teaching line */
#tutorial {
  position: absolute;
  top: 132px;
  left: 50%;
  transform: translateX(-50%);
  max-width: min(560px, calc(100vw - 48px));
  padding: 10px 18px;
  background: rgba(8, 14, 26, 0.62);
  border: 1px solid rgba(255, 210, 122, 0.32);
  border-radius: 6px;
  font-size: 12.5px;
  line-height: 1.5;
  letter-spacing: 0.04em;
  text-align: center;
  color: var(--ink);
  opacity: 0;
  transition: opacity 0.4s ease;
}
#tutorial:not(.hidden) { opacity: 1; }

/* Action progress bar (recover fill / fade countdown) */
#action-bar {
  position: absolute;
  bottom: 176px;
  left: 50%;
  transform: translateX(-50%);
  width: 220px;
  height: 6px;
  border-radius: 4px;
  background: rgba(232, 244, 255, 0.12);
  overflow: hidden;
}

#action-bar-fill {
  display: block;
  height: 100%;
  width: 0%;
  border-radius: 4px;
}

#action-bar.is-recover #action-bar-fill {
  background: linear-gradient(90deg, #3aa6c8, var(--accent));
  box-shadow: 0 0 10px rgba(111, 227, 255, 0.6);
}

#action-bar.is-fade #action-bar-fill {
  background: linear-gradient(90deg, #ff7a5c, var(--accent-warm));
  box-shadow: 0 0 10px rgba(255, 184, 107, 0.6);
}

/* Checkpoint record card (the middle-ground "anatomy") */
#ckpt-card {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) scale(0.96);
  width: min(340px, 86vw);
  padding: 18px 20px;
  background: rgba(8, 16, 28, 0.9);
  border: 1px solid rgba(111, 227, 255, 0.4);
  border-radius: 10px;
  box-shadow: 0 18px 60px rgba(2, 4, 10, 0.6), 0 0 30px rgba(111, 227, 255, 0.18);
  backdrop-filter: blur(6px);
  opacity: 0;
  transition: opacity 0.35s ease, transform 0.35s cubic-bezier(0.22, 1, 0.36, 1);
}

#ckpt-card:not(.hidden) {
  opacity: 1;
  transform: translate(-50%, -50%) scale(1);
}

.cc-head {
  font-size: 11px;
  letter-spacing: 0.22em;
  color: var(--accent);
}
#cc-id { color: var(--ink); }

.cc-summary {
  margin: 12px 0 14px;
  font-size: 15px;
  line-height: 1.4;
  letter-spacing: 0.02em;
}

.cc-attr {
  display: flex;
  align-items: center;
  gap: 10px;
}

.cc-attr-bar {
  position: relative;
  flex: 1;
  height: 6px;
  border-radius: 4px;
  background: rgba(255, 184, 107, 0.22);
  overflow: hidden;
}

#cc-attr-fill {
  position: absolute;
  inset: 0 auto 0 0;
  width: 70%;
  background: var(--accent);
}

#cc-attr-text {
  font-size: 10.5px;
  letter-spacing: 0.04em;
  opacity: 0.75;
  white-space: nowrap;
}

.cc-trailer {
  margin-top: 13px;
  padding-top: 11px;
  border-top: 1px solid rgba(111, 227, 255, 0.16);
  font-size: 11px;
  letter-spacing: 0.02em;
  color: rgba(232, 244, 255, 0.5);
}
.cc-trailer #cc-id { color: var(--accent); opacity: 1; }

.cc-foot {
  margin-top: 10px;
  font-size: 10px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--accent);
  opacity: 0.75;
}

/* Ship terminal — type the real commands */
#terminal {
  position: absolute;
  bottom: 70px;
  left: 50%;
  transform: translateX(-50%);
  width: min(560px, calc(100vw - 40px));
  padding: 14px 16px;
  background: rgba(4, 10, 18, 0.88);
  border: 1px solid rgba(111, 227, 255, 0.42);
  border-radius: 8px;
  box-shadow: 0 14px 40px rgba(2, 4, 10, 0.55), 0 0 24px rgba(111, 227, 255, 0.12);
  backdrop-filter: blur(6px);
  text-align: left;
}

#term-hint {
  font-size: 12.5px;
  letter-spacing: 0.02em;
  color: var(--ink);
  opacity: 0.68;
  margin-bottom: 10px;
}

#term-line {
  display: flex;
  align-items: center;
  font-size: 16px;
  letter-spacing: 0.02em;
}

.term-prompt {
  color: var(--accent);
  opacity: 0.9;
  margin-right: 8px;
}

#term-input { color: var(--ink); white-space: pre; }
#term-input.is-dim { color: var(--accent-warm); opacity: 0.92; }

/* Call-to-action: the actionable command/keys — the brightest thing here */
#term-cta {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 13px;
}
#term-cta:empty { display: none; }
.cta-label {
  font-size: 10px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: var(--accent);
  opacity: 0.9;
}
.cta-cmd {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: #04121a;
  padding: 5px 14px;
  border-radius: 7px;
  background: linear-gradient(90deg, #6fe3ff, #9af0ff);
  box-shadow: 0 0 18px rgba(111, 227, 255, 0.45);
}
.cta-key {
  display: inline-grid;
  place-items: center;
  min-width: 26px;
  height: 26px;
  padding: 0 7px;
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 14px;
  font-weight: 700;
  border-radius: 6px;
  color: #04121a;
}
.cta-key-yes {
  background: linear-gradient(90deg, #6fe3ff, #9af0ff);
  box-shadow: 0 0 14px rgba(111, 227, 255, 0.45);
}
.cta-key-no {
  background: rgba(232, 244, 255, 0.16);
  color: var(--ink);
  border: 1px solid rgba(232, 244, 255, 0.3);
}
.cta-note {
  font-size: 12.5px;
  color: var(--ink);
  opacity: 0.82;
  margin-right: 8px;
}

/* `entire checkpoint list` output */
#term-list:not(.hidden) {
  display: flex;
  flex-direction: column;
  gap: 5px;
  margin-top: 11px;
  padding-top: 10px;
  border-top: 1px solid rgba(111, 227, 255, 0.16);
}
.term-list-row {
  display: flex;
  gap: 12px;
  font-size: 12.5px;
  line-height: 1.3;
}
.tl-id { color: var(--accent); min-width: 300px; white-space: nowrap; }
.tl-key { color: var(--ink); opacity: 0.55; }
.tl-title { color: var(--ink); opacity: 0.82; }

/* Level 2 terminal output: search results, explain blocks, rewind browser.
   These rows carry a time column, so the id column shrinks to fit. */
.term-list-row .tl-time {
  color: var(--accent-warm);
  min-width: 44px;
  white-space: nowrap;
}
.term-list-row:has(.tl-time) .tl-id { min-width: 120px; }
.term-list-row .tl-sel { width: 12px; flex: none; color: #ff2bd6; }
.tl-exp-key { min-width: 90px; flex: none; }
.tl-anomaly { color: #ff8ad8; opacity: 0.95; }
.term-list-row.is-sel {
  background: rgba(255, 43, 214, 0.12);
  outline: 1px solid rgba(255, 43, 214, 0.35);
  border-radius: 4px;
}

.term-cursor {
  display: inline-block;
  width: 8px;
  height: 16px;
  background: var(--accent);
  animation: term-blink 1s steps(1) infinite;
}

@keyframes term-blink { 50% { opacity: 0; } }

#term-msg {
  min-height: 13px;
  margin-top: 9px;
  font-size: 11.5px;
  letter-spacing: 0.02em;
  opacity: 0;
  transition: opacity 0.15s ease;
}
#term-msg.show-ok { opacity: 0.92; color: #7cffb0; }
#term-msg.show-err { opacity: 0.92; color: #ff8a73; }

/* Map pin marking the landable island */
#island-pin {
  position: fixed;
  top: 0; left: 0;
  transform: translate(-50%, -100%);
  padding: 0;
  background: none;
  border: none;
  cursor: pointer;
  pointer-events: auto;
  z-index: 15;
  transition: filter 0.2s ease, transform 0.18s cubic-bezier(0.22, 1, 0.36, 1);
  transform-origin: bottom center;
  filter:
    drop-shadow(0 2px 4px var(--pin-shadow))
    drop-shadow(0 0 6px rgba(255, 184, 107, 0.3));
}
#island-pin .pin-svg { display: block; }
#island-pin .pin-svg path {
  fill: var(--pin-shell);
  stroke: var(--pin-rim);
  stroke-width: 1.35;
}
#island-pin .pin-svg circle {
  fill: var(--pin-core);
}
/* Hover (or keyboard focus, or synced from the 3D region) lifts the pin. */
#island-pin:hover,
#island-pin:focus-visible,
#island-pin.is-hot {
  transform: translate(-50%, -100%) scale(1.12);
  filter:
    drop-shadow(0 3px 5px var(--pin-shadow))
    drop-shadow(0 0 12px rgba(255, 184, 107, 0.62));
  outline: none;
}

/* After Level 1, the island's signal corrupts — the pin glitches magenta. */
#island-pin.is-corrupted .pin-svg circle { fill: #ff2bd6; }
#island-pin.is-corrupted .pin-svg path { stroke: rgba(255, 138, 216, 0.9); }
#island-pin.is-corrupted {
  filter:
    drop-shadow(0 2px 4px var(--pin-shadow))
    drop-shadow(0 0 10px rgba(255, 43, 214, 0.7));
  animation: pin-glitch 2.2s steps(2, end) infinite;
}
@keyframes pin-glitch {
  0%, 88% { transform: translate(-50%, -100%); }
  90% { transform: translate(calc(-50% - 2px), -100%) skewX(6deg); }
  94% { transform: translate(calc(-50% + 2px), -100%) skewX(-5deg); }
  97%, 100% { transform: translate(-50%, -100%); }
}

/* Crossfade overlay between views */
#fade {
  position: fixed;
  inset: 0;
  background: #07050f;
  opacity: 0;
  pointer-events: none;
  z-index: 40;
  transition: opacity 0.65s ease;
}
#fade.show { opacity: 1; }

/* First-person island HUD */
#crosshair {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 10px;
  height: 10px;
  margin: -5px 0 0 -5px;
  border: 1.5px solid rgba(255, 244, 232, 0.7);
  border-radius: 50%;
  box-shadow: 0 0 8px rgba(255, 210, 122, 0.6);
}

#fp-prompt {
  position: absolute;
  bottom: 138px;
  left: 50%;
  transform: translateX(-50%);
  width: max-content;
  max-width: calc(100vw - 36px);
  padding: 12px 22px;
  background: rgba(8, 14, 26, 0.7);
  border: 1px solid rgba(255, 210, 122, 0.4);
  border-radius: 6px;
  font-size: 14px;
  line-height: 1.45;
  letter-spacing: 0.12em;
  color: var(--ink);
  text-align: center;
  text-shadow: 0 0 12px rgba(255, 210, 122, 0.4);
}

#fp-controls {
  position: absolute;
  right: 28px;
  bottom: 28px;
  max-width: min(720px, calc(100vw - 56px));
  padding: 9px 12px;
  background: rgba(8, 14, 26, 0.54);
  border: 1px solid rgba(255, 244, 232, 0.18);
  border-radius: 6px;
  color: rgba(232, 244, 255, 0.72);
  font-size: 10px;
  line-height: 1;
  letter-spacing: 0;
}

#fp-controls:not(.hidden) {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: flex-end;
  gap: 10px 14px;
}

.control-item {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  min-height: 28px;
  white-space: nowrap;
}

.control-label {
  color: rgba(232, 244, 255, 0.68);
  letter-spacing: 0.05em;
}

.key {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 20px;
  height: 20px;
  padding: 0 5px;
  border: 1px solid rgba(255, 244, 232, 0.26);
  border-radius: 4px;
  background: rgba(255, 244, 232, 0.08);
  color: var(--ink);
  font-size: 10px;
  font-weight: 600;
  line-height: 1;
  box-shadow: inset 0 -1px 0 rgba(2, 4, 10, 0.4);
}

.key-wide {
  min-width: 30px;
}

.arrow-keys {
  display: grid;
  grid-template-columns: repeat(3, 18px);
  grid-template-rows: repeat(2, 18px);
  gap: 2px;
}

.arrow-keys .key {
  min-width: 18px;
  width: 18px;
  height: 18px;
  padding: 0;
  font-size: 9px;
}

.key-up { grid-column: 2; grid-row: 1; }
.key-left { grid-column: 1; grid-row: 2; }
.key-down { grid-column: 2; grid-row: 2; }
.key-right { grid-column: 3; grid-row: 2; }

.mouse-hint {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: rgba(232, 244, 255, 0.82);
}

.mouse-icon {
  position: relative;
  width: 13px;
  height: 19px;
  border: 1px solid rgba(255, 244, 232, 0.5);
  border-radius: 8px;
  background: rgba(255, 244, 232, 0.08);
}

.mouse-icon::before {
  content: "";
  position: absolute;
  top: 4px;
  left: 50%;
  width: 2px;
  height: 5px;
  transform: translateX(-50%);
  border-radius: 2px;
  background: rgba(255, 210, 122, 0.72);
}

@media (max-width: 680px) {
  #hint {
    bottom: 72px;
    max-width: calc(100vw - 36px);
    text-align: center;
    white-space: normal;
  }

  #audio-panel {
    top: auto;
    right: auto;
    bottom: 22px;
    left: 18px;
    gap: 6px;
    padding: 7px 8px;
  }

  .audio-mark {
    width: 28px;
    height: 28px;
  }

  .icon-button {
    width: 28px;
    height: 28px;
  }

  #audio-volume {
    width: 78px;
  }

  #fp-controls {
    top: 116px;
    right: 18px;
    bottom: auto;
    max-width: calc(100vw - 36px);
  }

  #fp-prompt {
    bottom: 82px;
  }

  #ship-meter {
    top: 14px;
    gap: 8px;
    padding: 7px 10px;
  }

  .meter-track { width: 120px; }

  #countdown {
    top: 14px;
    left: 16px;
    gap: 7px;
    padding: 7px 11px;
  }
  #countdown-time { font-size: 16px; min-width: 42px; }

  #dev-level-badge {
    top: 14px;
    left: 16px;
    padding: 7px 10px;
  }
  #dev-level-badge strong {
    font-size: 14px;
  }

  #tutorial {
    top: 56px;
    font-size: 11.5px;
    padding: 8px 12px;
  }

  #corrupt-meter {
    top: 14px;
    left: 16px;
    gap: 7px;
    padding: 7px 11px;
  }
  .cm-track { width: 84px; }
  #corrupt-pct { font-size: 13px; min-width: 36px; }

  #clue-tracker {
    top: 58px;
    left: 16px;
    padding: 6px 11px;
  }

  #action-bar { bottom: 120px; }

  #terminal {
    bottom: 56px;
    padding: 11px 12px;
  }
  #term-line { font-size: 13.5px; }
}

/* Loader */
#loader {
  position: fixed;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 22px;
  background: #02040a;
  z-index: 50;
  transition: opacity 0.8s ease;
}

#loader.done {
  opacity: 0;
  pointer-events: none;
}

.loader-ring {
  width: 46px;
  height: 46px;
  border: 2px solid rgba(111, 227, 255, 0.2);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 0.9s linear infinite;
}

.loader-text {
  font-size: 12px;
  letter-spacing: 0.35em;
  opacity: 0.7;
}

@keyframes spin { to { transform: rotate(360deg); } }

.hidden { display: none; }

