1	import * as THREE from "three";
2	import { createTerrain } from "./terrain.js";
3	import { createFirstPerson } from "./firstPerson.js";
4	import { BUILDERS } from "./debris.js";
5	import { makeBeamTexture, makeIceBlock, makeIdSprite } from "./memoryProps.js";
6	
7	// LEVEL 2 ("The Corruption") — the same island, revisited.
8	//
9	// One of the memories banked in Level 1 has soured, and a corruption is
10	// spreading across the island toward the ship terminal. You can't fix this
11	// forward — you go BACK, using the rest of the real Entire checkpoint suite:
12	//   inspect the frozen memories (E) → clue words
13	//   `entire checkpoint search "<clue>"`  → find candidate checkpoints
14	//   `entire checkpoint explain <id>`     → verify (one candidate is tainted)
15	//   `entire checkpoint rewind`           → browse + restore the last good state
16	//
17	// PRESSURE: the corruption zone grows from the soured memory toward the ship
18	// terminal. If it reaches the terminal, the run fails (R to retry). Rewinding
19	// to the WRONG checkpoint is a soft fail — the corruption surges, but you can
20	// always rewind again. That's the lesson: rewinding is safe and repeatable.
21	
22	const INTERACT_DIST = 8;     // how close (XZ) to inspect a frozen memory
23	const CONSOLE_DIST = 9;      // how close (XZ) to open the ship terminal
24	const START_RADIUS = 7;      // corruption radius at the start of a run
25	const SPREAD_RATE = 0.16;    // world units per second toward the ship
26	const SURGE = 6;             // radius jump when you rewind to a tainted checkpoint
27	const RESTORE_DUR = 4.5;     // seconds the good rewind takes to heal the island
28	const EDGE_BAND = 3.0;       // glowing front edge of the corruption zone
29	const ANOMALY = "03:47";     // when the corruption began — the key clue
30	
31	// The corruption spreads FROM the soured nav-panel memory TOWARD the ship
32	// terminal near the landing spot. Same island as Level 1, same placements.
33	const PLACEMENTS = [
34	  { x: -34, z: -28 },   // helmet
35	  { x: 40, z: -18 },    // logbook
36	  { x: 28, z: 38 },     // nav panel — the corruption's origin
37	];
38	const ORIGIN = PLACEMENTS[2];
39	const CONSOLE_POS = { x: -6, z: 56 };
40	
41	// The checkpoint ids the player banked in Level 1 (fixed so Level 2's fiction
42	// is stable across runs), shown on the frozen memories' trailer sprites.
43	const BANKED_IDS = ["31f0cafe4d12", "7e11a2b09c44", "b0a7ded51a6e"];
44	
45	// Inspecting each frozen memory yields a clue: searchable words from before
46	// the storm, and — on the soured panel — the anomaly timestamp itself.
47	const CLUES = [
48	  {
49	    kind: "helmet", title: "Abandoned EVA Helmet", key: "course plot",
50	    body: "The logger still loops a calm voice from before the storm: " +
51	      "“course plot steady… nav core in tune.”",
52	  },
53	  {
54	    kind: "logbook", title: "Torn Logbook Page", key: "landing vector",
55	    body: "A margin note, underlined twice: “landing vector locked — " +
56	      "do not touch after the storm.”",
57	  },
58	  {
59	    kind: "panel", title: "Cracked Nav Panel", key: `anomaly began ${ANOMALY}`,
60	    body: "The first glitch burned its timestamp into the glass: " +
61	      `${ANOMALY}. Anything written after that moment is tainted.`,
62	    origin: true,
63	  },
64	];
