66	// The ship's checkpoint log — what search/explain/rewind operate on. One is
67	// the last good nav state; one is a tempting decoy written AFTER the anomaly.
68	const CHECKPOINTS = [
69	  {
70	    id: "8c21d4e7a90f", time: "03:12", good: true,
71	    summary: "nav core calibrated — course plot locked to the landing vector",
72	    files: "nav/core.cfg · nav/course.plot",
