101	// Sky palette — the island starts under a sick dusk and drains toward a
102	// magenta-black void as the corruption closes in; the good rewind restores
103	// Level 1's calm lavender.
104	const SKY_SICK = new THREE.Color(0x221c3e);
105	const SKY_VOID = new THREE.Color(0x1c0618);
106	const FOG_SICK = new THREE.Color(0x221c3e);
107	const FOG_VOID = new THREE.Color(0x2a0a26);
108	const DOME_SICK = new THREE.Color(0x2e2752);
