111	const SUN_VOID = new THREE.Color(0xd23aa0);
112	const SKY_HEALED = new THREE.Color(0x2a2350);
113	const DOME_HEALED = new THREE.Color(0x3a3168);
114	const SUN_HEALED = new THREE.Color(0xfff1dc);
115	
116	// Corruption ground colors (vertex-color space, 0..1 rgb).
117	const C_VOID = [0.05, 0.025, 0.09];     // consumed land
118	const C_EDGE = [0.85, 0.12, 0.62];      // glowing magenta front
119	
120	function normalizeCmd(s) {
121	  return s.trim().toLowerCase().replace(/\s+/g, " ");
122	}
