124	// The glitching ship console the terminal lives in.
125	function makeConsole() {
126	  const g = new THREE.Group();
127	  const pedestal = new THREE.Mesh(
128	    new THREE.BoxGeometry(2.6, 4.6, 1.6),
129	    new THREE.MeshStandardMaterial({ color: 0x1c2230, metalness: 0.6, roughness: 0.35 })
130	  );
131	  pedestal.position.y = 2.3;
132	  const screen = new THREE.Mesh(
133	    new THREE.PlaneGeometry(2.1, 1.3),
134	    new THREE.MeshStandardMaterial({
135	      color: 0x0c2030, emissive: 0x2a8aa6, emissiveIntensity: 1.4, roughness: 0.3,
136	    })
137	  );
138	  screen.position.set(0, 4.0, 0.82);
139	  screen.rotation.x = -0.28;
140	  g.add(pedestal, screen);
141	  g.userData.screen = screen;
