145	export function createCorruptionView(renderer, { onExit } = {}) {
146	  const canvas = renderer.domElement;
147	
148	  // ---------- scene & sky ----------
149	  const scene = new THREE.Scene();
150	  scene.background = SKY_SICK.clone();
151	  scene.fog = new THREE.Fog(FOG_SICK.clone(), 90, 320);
152	
153	  const camera = new THREE.PerspectiveCamera(
154	    62, window.innerWidth / window.innerHeight, 0.1, 2000
155	  );
156	
157	  // ---------- lighting (the same island, but the light has gone wrong) ----------
158	  scene.add(new THREE.HemisphereLight(0xa898d8, 0x2a2248, 0.55));
159	  const sun = new THREE.DirectionalLight(SUN_SICK, 1.1);
160	  sun.position.set(60, 90, 40);
161	  scene.add(sun);
162	  scene.add(new THREE.AmbientLight(0x5a4c82, 0.3));
163	
164	  const dome = new THREE.Mesh(
165	    new THREE.SphereGeometry(900, 32, 16),
166	    new THREE.MeshBasicMaterial({ color: DOME_SICK.clone(), side: THREE.BackSide, fog: false })
167	  );
168	  scene.add(dome);
169	
170	  // ---------- terrain (Level 1's island, with a recolorable wound) ----------
171	  const terrain = createTerrain({ size: 200, segments: 220, maxHeight: 26, seed: 1337 });
172	  scene.add(terrain.mesh, terrain.water);
173	
174	  // Per-vertex distance from the corruption origin + pristine colors, so the
175	  // zone can be repainted (and healed) every frame without re-noising.
176	  const geo = terrain.mesh.geometry;
177	  const posAttr = geo.attributes.position;
178	  const colAttr = geo.attributes.color;
179	  const baseColors = colAttr.array.slice();
180	  const vertDist = new Float32Array(posAttr.count);
181	  for (let v = 0; v < posAttr.count; v++) {
182	    vertDist[v] = Math.hypot(posAttr.getX(v) - ORIGIN.x, posAttr.getZ(v) - ORIGIN.z);
183	  }
184	
185	  // ---------- the banked memories, frozen since Level 1 ----------
186	  const artifacts = [];
187	  CLUES.forEach((clue, idx) => {
188	    const place = PLACEMENTS[idx];
189	    const groundY = terrain.heightAt(place.x, place.z);
190	    const anchor = new THREE.Group();
191	    anchor.position.set(place.x, groundY, place.z);
192	
193	    const model = BUILDERS[clue.kind]();
194	    model.scale.setScalar(14);
195	    model.position.y = 1.4;
196	    anchor.add(model);
197	
198	    const ice = makeIceBlock();
199	    ice.position.y = 2.0;
200	    ice.material.emissive.setHex(0x2a6c8a);
201	    ice.material.emissiveIntensity = 1.1;
202	    anchor.add(ice);
203	
204	    const spr = makeIdSprite(BANKED_IDS[idx]);
205	    spr.position.y = ice.position.y + 5;
206	    anchor.add(spr);
207	
208	    const glow = new THREE.PointLight(0x8fe3ff, 5, 26, 2);
209	    glow.position.y = 3;
210	    anchor.add(glow);
211	
212	    scene.add(anchor);
213	    artifacts.push({
214	      anchor, model, ice, glow, clue,
215	      iceBaseX: ice.position.x, iceBaseY: ice.position.y,
216	      distFromOrigin: Math.hypot(place.x - ORIGIN.x, place.z - ORIGIN.z),
217	      inspected: false,
218	    });
219	  });
220	
221	  // ---------- the ship terminal (the thing the corruption is coming for) ----------
222	  const consoleAnchor = new THREE.Group();
223	  consoleAnchor.position.set(
224	    CONSOLE_POS.x, terrain.heightAt(CONSOLE_POS.x, CONSOLE_POS.z), CONSOLE_POS.z
225	  );
226	  const consoleProp = makeConsole();
227	  consoleAnchor.add(consoleProp);
228	
229	  // A cyan beam so the terminal is findable from anywhere on the island.
230	  const beamTex = makeBeamTexture();
231	  const consoleBeam = new THREE.Mesh(
232	    new THREE.CylinderGeometry(0.6, 0.6, 60, 12, 1, true),
233	    new THREE.MeshBasicMaterial({
234	      map: beamTex, color: 0x6fe3ff, transparent: true, opacity: 0.4,
235	      blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide,
236	      fog: false,
237	    })
238	  );
239	  consoleBeam.position.y = 30;
240	  consoleAnchor.add(consoleBeam);
241	  const consoleGlow = new THREE.PointLight(0x6fe3ff, 6, 30, 2);
242	  consoleGlow.position.y = 5;
243	  consoleAnchor.add(consoleGlow);
244	  scene.add(consoleAnchor);
245	
246	  // The run fails when the corruption front reaches the terminal.
247	  const FAIL_RADIUS = Math.hypot(ORIGIN.x - CONSOLE_POS.x, ORIGIN.z - CONSOLE_POS.z) - 2;
248	
249	  // ---------- corruption motes (glitch particles drifting over the wound) ----------
250	  const MOTES = 260;
251	  const moteFrac = new Float32Array(MOTES);   // 0..1 of the current radius
252	  const moteAng = new Float32Array(MOTES);
253	  const motePhase = new Float32Array(MOTES);
254	  for (let i = 0; i < MOTES; i++) {
255	    moteFrac[i] = Math.pow(Math.random(), 0.6);
256	    moteAng[i] = Math.random() * Math.PI * 2;
257	    motePhase[i] = Math.random() * 10;
258	  }
259	  const moteGeo = new THREE.BufferGeometry();
260	  moteGeo.setAttribute("position", new THREE.BufferAttribute(new Float32Array(MOTES * 3), 3));
261	  const motes = new THREE.Points(moteGeo, new THREE.PointsMaterial({
262	    color: 0xff2bd6, size: 0.7, transparent: true, opacity: 0.75,
263	    blending: THREE.AdditiveBlending, depthWrite: false,
264	  }));
265	  scene.add(motes);
266	
267	  // ---------- first-person controller ----------
268	  const fp = createFirstPerson(camera, canvas, {
269	    heightAt: terrain.heightAt,
270	    radius: terrain.radius * 0.96,
271	    eyeHeight: 2.6,
272	    speed: 24,
273	  });
274	  scene.add(fp.controls.object);
275	
276	  // ---------- HUD elements (shared FP set + Level 2's own) ----------
277	  const promptEl = document.getElementById("fp-prompt");
278	  const controlsEl = document.getElementById("fp-controls");
279	  const crosshair = document.getElementById("crosshair");
280	  const tutorialEl = document.getElementById("tutorial");
281	  const fpShared = document.getElementById("fp-shared");
282	  const termEl = document.getElementById("terminal");
283	  const termHint = document.getElementById("term-hint");
