299	  const winEl = document.getElementById("l2-win");
300	  const winSub = document.getElementById("l2-win-sub");
301	  const failEl = document.getElementById("l2-fail");
302	  const glitchFlash = document.getElementById("glitch-flash");
303	
304	  let active = false;
305	  let started = false;          // briefing dismissed → corruption + movement go live
306	  let failed = false;
307	  let restoring = false;        // the good rewind is playing out
308	  let restored = false;         // the level is won
309	  let restoreT = 0;
310	  let restoreFrom = START_RADIUS;
311	  let promptText = null;
312	  let controlsLocked = null;
