335	  const anomalyKnown = () => artifacts[2].inspected;
336	  const browserList = () => [...CHECKPOINTS].sort((a, b) => (a.time < b.time ? 1 : -1));
337	
338	  // ---------- HUD helpers ----------
339	  function setPrompt(text) {
340	    if (!promptEl || text === promptText) return;
341	    promptText = text;
342	    if (text) { promptEl.textContent = text; promptEl.classList.remove("hidden"); }
343	    else promptEl.classList.add("hidden");
344	  }
345	  function showTutorial(text, ms = 5500) {
346	    if (!tutorialEl) return;
347	    clearTimeout(tutorialTimer);
348	    tutorialEl.textContent = text;
349	    tutorialEl.classList.remove("hidden");
350	    if (ms > 0) tutorialTimer = setTimeout(() => tutorialEl.classList.add("hidden"), ms);
