396	  // ---------- corruption meter ----------
397	  function corruptionPct() {
398	    return Math.min(100, Math.round(
399	      ((radius - START_RADIUS) / (FAIL_RADIUS - START_RADIUS)) * 100
400	    ));
401	  }
402	  function updateMeter() {
403	    const pct = restored ? 0 : corruptionPct();
404	    if (corruptFill) corruptFill.style.width = pct + "%";
405	    if (corruptPct) corruptPct.textContent = pct + "%";
