410	  // ---------- the spreading wound ----------
411	  // Repaint terrain vertex colors around the front every frame: consumed land
412	  // collapses to void, with a flickering magenta band at the leading edge.
413	  function paintCorruption(t) {
414	    const cols = colAttr.array;
415	    const flicker = 0.75 + 0.25 * Math.sin(t * 9);
416	    const reach = radius + EDGE_BAND;
417	    for (let v = 0; v < posAttr.count; v++) {
418	      const d = vertDist[v];
419	      const i = v * 3;
420	      if (d >= reach) {
421	        if (cols[i] !== baseColors[i] || cols[i + 1] !== baseColors[i + 1]) {
422	          cols[i] = baseColors[i];
423	          cols[i + 1] = baseColors[i + 1];
424	          cols[i + 2] = baseColors[i + 2];
425	        }
426	        continue;
427	      }
428	      if (d <= radius) {
429	        // Inside the wound — sink to void, deeper toward the origin.
430	        const k = Math.min(1, (radius - d) / 10 + 0.45);
431	        cols[i] = baseColors[i] + (C_VOID[0] - baseColors[i]) * k;
432	        cols[i + 1] = baseColors[i + 1] + (C_VOID[1] - baseColors[i + 1]) * k;
433	        cols[i + 2] = baseColors[i + 2] + (C_VOID[2] - baseColors[i + 2]) * k;
434	      } else {
435	        // The leading edge — a thin magenta burn.
436	        const k = (1 - (d - radius) / EDGE_BAND) * flicker;
437	        cols[i] = baseColors[i] + (C_EDGE[0] - baseColors[i]) * k;
438	        cols[i + 1] = baseColors[i + 1] + (C_EDGE[1] - baseColors[i + 1]) * k;
439	        cols[i + 2] = baseColors[i + 2] + (C_EDGE[2] - baseColors[i + 2]) * k;
440	      }
441	    }
442	    colAttr.needsUpdate = true;
443	  }
