445	  function updateMotes(t) {
446	    const arr = moteGeo.attributes.position.array;
447	    for (let i = 0; i < MOTES; i++) {
448	      const r = moteFrac[i] * radius;
449	      const x = ORIGIN.x + Math.cos(moteAng[i] + t * 0.05) * r;
450	      const z = ORIGIN.z + Math.sin(moteAng[i] + t * 0.05) * r;
451	      arr[i * 3] = x;
452	      arr[i * 3 + 1] = terrain.heightAt(x, z) + 1.2 +
453	        Math.sin(t * 1.6 + motePhase[i]) * 1.0 + ((t * 0.8 + motePhase[i]) % 3);
454	      arr[i * 3 + 2] = z;
455	    }
456	    moteGeo.attributes.position.needsUpdate = true;
457	    motes.material.opacity = restored ? 0 : 0.45 + 0.3 * Math.sin(t * 7);
458	  }
