460	  // Sky drains toward the void as the corruption nears the terminal; a good
461	  // rewind lerps everything back to Level 1's calm lavender.
462	  function applySky() {
463	    if (restored || restoring) {
464	      const k = restoring ? Math.min(1, restoreT / RESTORE_DUR) : 1;
465	      scene.background.copy(SKY_SICK).lerp(SKY_HEALED, k);
466	      scene.fog.color.copy(FOG_SICK).lerp(SKY_HEALED, k);
467	      dome.material.color.copy(DOME_SICK).lerp(DOME_HEALED, k);
468	      sun.color.copy(SUN_SICK).lerp(SUN_HEALED, k);
469	      return;
470	    }
471	    let p = corruptionPct() / 100;
472	    if (failed) p = 1;
473	    p *= p;
474	    if (p > 0.55) p += 0.1 * (0.5 + 0.5 * Math.sin(performance.now() / 120));
475	    p = Math.min(1, p);
476	    scene.background.copy(SKY_SICK).lerp(SKY_VOID, p);
477	    scene.fog.color.copy(FOG_SICK).lerp(FOG_VOID, p);
478	    dome.material.color.copy(DOME_SICK).lerp(DOME_VOID, p);
479	    sun.color.copy(SUN_SICK).lerp(SUN_VOID, p * 0.9);
480	  }
