629	  // ---------- entire checkpoint search ----------
630	  function doSearch(raw) {
631	    const q = raw.replace(/^.*?search/i, "").replace(/["']/g, "").trim().toLowerCase();
632	    const words = q.split(/\s+/).filter((w) => w.length >= 3);
633	    if (!words.length) {
634	      flashTerminal('search needs words — try:  entire checkpoint search "course plot"', false);
635	      return;
636	    }
637	    const scored = CHECKPOINTS
638	      .map((cp) => ({
639	        cp,
640	        score: words.filter((w) => cp.summary.toLowerCase().includes(w)).length,
641	      }))
642	      .filter((r) => r.score > 0)
643	      .sort((a, b) => b.score - a.score || (a.cp.time < b.cp.time ? 1 : -1));
644	    if (!scored.length) {
645	      flashTerminal(`0 results for “${q}” — try words from the memories you inspected`, false);
646	      return;
647	    }
648	    searched = true;
649	    lastResults = scored.map((r) => r.cp);
650	    if (termList) {
651	      termList.innerHTML = lastResults.map((cp) =>
652	        `<div class="term-list-row"><span class="tl-id">${cp.id}</span>` +
653	        `<span class="tl-time">${cp.time}</span>` +
654	        `<span class="tl-title">${cp.summary}</span></div>`
655	      ).join("");
656	      termList.classList.remove("hidden");
657	    }
658	    flashTerminal(`${lastResults.length} checkpoint${lastResults.length === 1 ? "" : "s"} matched “${q}”`, true);
659	    teachOnce("searched",
660	      "Each result is a moment you can return to. `entire checkpoint explain <id>` shows what's inside one.", 8000);
661	  }
