794	  function onKeyDown(e) {
795	    if (!active) return;
796	
797	    // Briefing is up — Enter/Space begins the run, nothing else.
798	    if (!started) {
799	      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
800	      return;
801	    }
802	
803	    // The corruption won — only R (retry) does anything.
804	    if (failed) {
805	      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
806	      return;
807	    }
808	
809	    // Reading a clue — E or Esc puts it down.
810	    if (openClue) {
811	      if (e.code === "KeyE" || e.code === "Escape") { closeClue(); e.preventDefault(); }
812	      return;
813	    }
814	
815	    // While the terminal is open, all keys feed it.
816	    if (terminalOpen) {
817	      if (confirmTarget) {
818	        if (e.key === "y" || e.key === "Y") { applyRewind(confirmTarget); e.preventDefault(); return; }
819	        if (e.key === "n" || e.key === "N" || e.code === "Escape") {
820	          confirmTarget = null;
821	          openBrowser();             // back to the browser, nothing lost
822	          e.preventDefault();
823	          return;
824	        }
825	        e.preventDefault();
826	        return;
827	      }
828	      if (browserMode) {
829	        const list = browserList();
830	        if (e.code === "ArrowUp") { browserSel = (browserSel + list.length - 1) % list.length; renderBrowser(); e.preventDefault(); return; }
831	        if (e.code === "ArrowDown") { browserSel = (browserSel + 1) % list.length; renderBrowser(); e.preventDefault(); return; }
832	        if (e.code === "Enter") {
833	          browserMode = false;
834	          confirmTarget = list[browserSel];
835	          termList?.classList.add("hidden");
836	          renderTerminal();
837	          e.preventDefault();
838	          return;
839	        }
840	        if (e.code === "Escape") {
841	          browserMode = false;
842	          termInput.classList.remove("is-dim");
843	          termList?.classList.add("hidden");
844	          renderTerminal();
845	          e.preventDefault();
846	          return;
847	        }
848	        e.preventDefault();
849	        return;
850	      }
851	      if (e.code === "Escape") { closeTerminal(true); e.preventDefault(); return; }
852	      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
853	      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
854	      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
855	        buffer += e.key;
856	        renderTerminal();
857	        e.preventDefault();
858	      }
859	      return;
860	    }
861	
862	    // Walking around.
863	    if (e.code === "KeyE" && nearArtifact) { openClueCard(nearArtifact); e.preventDefault(); return; }
864	    if (e.code === "Escape" && fp.isLocked) fp.unlock();
865	    if (e.code === "KeyB") onExit?.();
