import * as THREE from "three";
import { createTerrain } from "./terrain.js";
import { createFirstPerson } from "./firstPerson.js";
import { BUILDERS } from "./debris.js";
import { makeBeamTexture, makeIceBlock, makeIdSprite } from "./memoryProps.js";

// LEVEL 2 ("The Corruption") — the same island, revisited.
//
// One of the memories banked in Level 1 has soured, and a corruption is
// spreading across the island toward the ship terminal. You can't fix this
// forward — you go BACK, using the rest of the real Entire checkpoint suite:
//   inspect the frozen memories (E) → clue words
//   `entire checkpoint search "<clue>"`  → find candidate checkpoints
//   `entire checkpoint explain <id>`     → verify (one candidate is tainted)
//   `entire checkpoint rewind`           → browse + restore the last good state
//
// PRESSURE: the corruption zone grows from the soured memory toward the ship
// terminal. If it reaches the terminal, the run fails (R to retry). Rewinding
// to the WRONG checkpoint is a soft fail — the corruption surges, but you can
// always rewind again. That's the lesson: rewinding is safe and repeatable.

const INTERACT_DIST = 8;     // how close (XZ) to inspect a frozen memory
const CONSOLE_DIST = 9;      // how close (XZ) to open the ship terminal
const START_RADIUS = 7;      // corruption radius at the start of a run
const SPREAD_RATE = 0.16;    // world units per second toward the ship
const SURGE = 6;             // radius jump when you rewind to a tainted checkpoint
const RESTORE_DUR = 4.5;     // seconds the good rewind takes to heal the island
const EDGE_BAND = 3.0;       // glowing front edge of the corruption zone
const ANOMALY = "03:47";     // when the corruption began — the key clue

// The corruption spreads FROM the soured nav-panel memory TOWARD the ship
// terminal near the landing spot. Same island as Level 1, same placements.
const PLACEMENTS = [
  { x: -34, z: -28 },   // helmet
  { x: 40, z: -18 },    // logbook
  { x: 28, z: 38 },     // nav panel — the corruption's origin
];
const ORIGIN = PLACEMENTS[2];
const CONSOLE_POS = { x: -6, z: 56 };

// The checkpoint ids the player banked in Level 1 (fixed so Level 2's fiction
// is stable across runs), shown on the frozen memories' trailer sprites.
const BANKED_IDS = ["31f0cafe4d12", "7e11a2b09c44", "b0a7ded51a6e"];

// Inspecting each frozen memory yields a clue: searchable words from before
// the storm, and — on the soured panel — the anomaly timestamp itself.
const CLUES = [
  {
    kind: "helmet", title: "Abandoned EVA Helmet", key: "course plot",
    body: "The logger still loops a calm voice from before the storm: " +
      "“course plot steady… nav core in tune.”",
  },
  {
    kind: "logbook", title: "Torn Logbook Page", key: "landing vector",
    body: "A margin note, underlined twice: “landing vector locked — " +
      "do not touch after the storm.”",
  },
  {
    kind: "panel", title: "Cracked Nav Panel", key: `anomaly began ${ANOMALY}`,
    body: "The first glitch burned its timestamp into the glass: " +
      `${ANOMALY}. Anything written after that moment is tainted.`,
    origin: true,
  },
];

// The ship's checkpoint log — what search/explain/rewind operate on. One is
// the last good nav state; one is a tempting decoy written AFTER the anomaly.
const CHECKPOINTS = [
  {
    id: "8c21d4e7a90f", time: "03:12", good: true,
    summary: "nav core calibrated — course plot locked to the landing vector",
    files: "nav/core.cfg · nav/course.plot",
    session: "previous crew · 7 prompts · 18.2k tokens",
  },
  {
    id: "e4f1b8a2c356", time: "04:02", tainted: true,
    summary: "emergency patch — course plot rebuilt, landing vector rerouted",
    files: "nav/core.cfg · nav/override.bin",
    session: "previous crew · 2 prompts · 4.1k tokens",
  },
  {
    id: "6a45e9b3d2f7", time: "04:15", tainted: true,
    summary: "hull sealant reapplied after the first glitch storm",
    files: "hull/seams.log",
    session: "previous crew · 1 prompt · 1.8k tokens",
  },
  {
    id: "2b90cc41d7ae", time: "02:31",
    summary: "ballast trim balanced for the lavender sea crossing",
    files: "hull/ballast.cfg",
    session: "previous crew · 3 prompts · 6.4k tokens",
  },
  {
    id: "f7d3a2e85c10", time: "01:58",
    summary: "antenna sweep — long-range dispatch tested",
    files: "comms/antenna.cal",
    session: "previous crew · 4 prompts · 9.0k tokens",
  },
];

// Sky palette — the island starts under a sick dusk and drains toward a
// magenta-black void as the corruption closes in; the good rewind restores
// Level 1's calm lavender.
const SKY_SICK = new THREE.Color(0x221c3e);
const SKY_VOID = new THREE.Color(0x1c0618);
const FOG_SICK = new THREE.Color(0x221c3e);
const FOG_VOID = new THREE.Color(0x2a0a26);
const DOME_SICK = new THREE.Color(0x2e2752);
const DOME_VOID = new THREE.Color(0x33071f);
const SUN_SICK = new THREE.Color(0xcdb8e8);
const SUN_VOID = new THREE.Color(0xd23aa0);
const SKY_HEALED = new THREE.Color(0x2a2350);
const DOME_HEALED = new THREE.Color(0x3a3168);
const SUN_HEALED = new THREE.Color(0xfff1dc);

// Corruption ground colors (vertex-color space, 0..1 rgb).
const C_VOID = [0.05, 0.025, 0.09];     // consumed land
const C_EDGE = [0.85, 0.12, 0.62];      // glowing magenta front

function normalizeCmd(s) {
  return s.trim().toLowerCase().replace(/\s+/g, " ");
}

// The glitching ship console the terminal lives in.
function makeConsole() {
  const g = new THREE.Group();
  const pedestal = new THREE.Mesh(
    new THREE.BoxGeometry(2.6, 4.6, 1.6),
    new THREE.MeshStandardMaterial({ color: 0x1c2230, metalness: 0.6, roughness: 0.35 })
  );
  pedestal.position.y = 2.3;
  const screen = new THREE.Mesh(
    new THREE.PlaneGeometry(2.1, 1.3),
    new THREE.MeshStandardMaterial({
      color: 0x0c2030, emissive: 0x2a8aa6, emissiveIntensity: 1.4, roughness: 0.3,
    })
  );
  screen.position.set(0, 4.0, 0.82);
  screen.rotation.x = -0.28;
  g.add(pedestal, screen);
  g.userData.screen = screen;
  return g;
}

export function createCorruptionView(renderer, { onExit } = {}) {
  const canvas = renderer.domElement;

  // ---------- scene & sky ----------
  const scene = new THREE.Scene();
  scene.background = SKY_SICK.clone();
  scene.fog = new THREE.Fog(FOG_SICK.clone(), 90, 320);

  const camera = new THREE.PerspectiveCamera(
    62, window.innerWidth / window.innerHeight, 0.1, 2000
  );

  // ---------- lighting (the same island, but the light has gone wrong) ----------
  scene.add(new THREE.HemisphereLight(0xa898d8, 0x2a2248, 0.55));
  const sun = new THREE.DirectionalLight(SUN_SICK, 1.1);
  sun.position.set(60, 90, 40);
  scene.add(sun);
  scene.add(new THREE.AmbientLight(0x5a4c82, 0.3));

  const dome = new THREE.Mesh(
    new THREE.SphereGeometry(900, 32, 16),
    new THREE.MeshBasicMaterial({ color: DOME_SICK.clone(), side: THREE.BackSide, fog: false })
  );
  scene.add(dome);

  // ---------- terrain (Level 1's island, with a recolorable wound) ----------
  const terrain = createTerrain({ size: 200, segments: 220, maxHeight: 26, seed: 1337 });
  scene.add(terrain.mesh, terrain.water);

  // Per-vertex distance from the corruption origin + pristine colors, so the
  // zone can be repainted (and healed) every frame without re-noising.
  const geo = terrain.mesh.geometry;
  const posAttr = geo.attributes.position;
  const colAttr = geo.attributes.color;
  const baseColors = colAttr.array.slice();
  const vertDist = new Float32Array(posAttr.count);
  for (let v = 0; v < posAttr.count; v++) {
    vertDist[v] = Math.hypot(posAttr.getX(v) - ORIGIN.x, posAttr.getZ(v) - ORIGIN.z);
  }

  // ---------- the banked memories, frozen since Level 1 ----------
  const artifacts = [];
  CLUES.forEach((clue, idx) => {
    const place = PLACEMENTS[idx];
    const groundY = terrain.heightAt(place.x, place.z);
    const anchor = new THREE.Group();
    anchor.position.set(place.x, groundY, place.z);

    const model = BUILDERS[clue.kind]();
    model.scale.setScalar(14);
    model.position.y = 1.4;
    anchor.add(model);

    const ice = makeIceBlock();
    ice.position.y = 2.0;
    ice.material.emissive.setHex(0x2a6c8a);
    ice.material.emissiveIntensity = 1.1;
    anchor.add(ice);

    const spr = makeIdSprite(BANKED_IDS[idx]);
    spr.position.y = ice.position.y + 5;
    anchor.add(spr);

    const glow = new THREE.PointLight(0x8fe3ff, 5, 26, 2);
    glow.position.y = 3;
    anchor.add(glow);

    scene.add(anchor);
    artifacts.push({
      anchor, model, ice, glow, clue,
      iceBaseX: ice.position.x, iceBaseY: ice.position.y,
      distFromOrigin: Math.hypot(place.x - ORIGIN.x, place.z - ORIGIN.z),
      inspected: false,
    });
  });

  // ---------- the ship terminal (the thing the corruption is coming for) ----------
  const consoleAnchor = new THREE.Group();
  consoleAnchor.position.set(
    CONSOLE_POS.x, terrain.heightAt(CONSOLE_POS.x, CONSOLE_POS.z), CONSOLE_POS.z
  );
  const consoleProp = makeConsole();
  consoleAnchor.add(consoleProp);

  // A cyan beam so the terminal is findable from anywhere on the island.
  const beamTex = makeBeamTexture();
  const consoleBeam = new THREE.Mesh(
    new THREE.CylinderGeometry(0.6, 0.6, 60, 12, 1, true),
    new THREE.MeshBasicMaterial({
      map: beamTex, color: 0x6fe3ff, transparent: true, opacity: 0.4,
      blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide,
      fog: false,
    })
  );
  consoleBeam.position.y = 30;
  consoleAnchor.add(consoleBeam);
  const consoleGlow = new THREE.PointLight(0x6fe3ff, 6, 30, 2);
  consoleGlow.position.y = 5;
  consoleAnchor.add(consoleGlow);
  scene.add(consoleAnchor);

  // The run fails when the corruption front reaches the terminal.
  const FAIL_RADIUS = Math.hypot(ORIGIN.x - CONSOLE_POS.x, ORIGIN.z - CONSOLE_POS.z) - 2;

  // ---------- corruption motes (glitch particles drifting over the wound) ----------
  const MOTES = 260;
  const moteFrac = new Float32Array(MOTES);   // 0..1 of the current radius
  const moteAng = new Float32Array(MOTES);
  const motePhase = new Float32Array(MOTES);
  for (let i = 0; i < MOTES; i++) {
    moteFrac[i] = Math.pow(Math.random(), 0.6);
    moteAng[i] = Math.random() * Math.PI * 2;
    motePhase[i] = Math.random() * 10;
  }
  const moteGeo = new THREE.BufferGeometry();
  moteGeo.setAttribute("position", new THREE.BufferAttribute(new Float32Array(MOTES * 3), 3));
  const motes = new THREE.Points(moteGeo, new THREE.PointsMaterial({
    color: 0xff2bd6, size: 0.7, transparent: true, opacity: 0.75,
    blending: THREE.AdditiveBlending, depthWrite: false,
  }));
  scene.add(motes);

  // ---------- first-person controller ----------
  const fp = createFirstPerson(camera, canvas, {
    heightAt: terrain.heightAt,
    radius: terrain.radius * 0.96,
    eyeHeight: 2.6,
    speed: 24,
  });
  scene.add(fp.controls.object);

  // ---------- HUD elements (shared FP set + Level 2's own) ----------
  const promptEl = document.getElementById("fp-prompt");
  const controlsEl = document.getElementById("fp-controls");
  const crosshair = document.getElementById("crosshair");
  const tutorialEl = document.getElementById("tutorial");
  const fpShared = document.getElementById("fp-shared");
  const termEl = document.getElementById("terminal");
  const termHint = document.getElementById("term-hint");
  const termInput = document.getElementById("term-input");
  const termList = document.getElementById("term-list");
  const termMsg = document.getElementById("term-msg");
  const termCta = document.getElementById("term-cta");
  const l2Hud = document.getElementById("l2-hud");
  const briefingEl = document.getElementById("l2-briefing");
  const briefingStartBtn = document.getElementById("l2-briefing-start");
  const corruptMeter = document.getElementById("corrupt-meter");
  const corruptFill = document.getElementById("corrupt-fill");
  const corruptPct = document.getElementById("corrupt-pct");
  const clueCount = document.getElementById("clue-count");
  const clueCard = document.getElementById("clue-card");
  const clueTitle = document.getElementById("clue-title");
  const clueBody = document.getElementById("clue-body");
  const clueKey = document.getElementById("clue-key");
  const winEl = document.getElementById("l2-win");
  const winSub = document.getElementById("l2-win-sub");
  const failEl = document.getElementById("l2-fail");
  const glitchFlash = document.getElementById("glitch-flash");

  let active = false;
  let started = false;          // briefing dismissed → corruption + movement go live
  let failed = false;
  let restoring = false;        // the good rewind is playing out
  let restored = false;         // the level is won
  let restoreT = 0;
  let restoreFrom = START_RADIUS;
  let promptText = null;
  let controlsLocked = null;
  const taught = new Set();
  let tutorialTimer = null;
  let msgTimer = null;

  // Corruption state — radius is the single source of pressure.
  let radius = START_RADIUS;

  // Terminal state.
  let terminalOpen = false;
  let buffer = "";
  let consoleDismissed = false; // player Esc'd the terminal (until they walk away)
  let browserMode = false;      // `entire checkpoint rewind` browser is up
  let browserSel = 0;
  let confirmTarget = null;     // checkpoint awaiting the rewind y/n
  let openClue = null;          // the clue card being read (movement frozen)

  // Investigation progress.
  let searched = false;
  let lastResults = [];
  const explained = new Set();

  const cluesFound = () => artifacts.filter((a) => a.inspected).length;
  const anomalyKnown = () => artifacts[2].inspected;
  const browserList = () => [...CHECKPOINTS].sort((a, b) => (a.time < b.time ? 1 : -1));

  // ---------- HUD helpers ----------
  function setPrompt(text) {
    if (!promptEl || text === promptText) return;
    promptText = text;
    if (text) { promptEl.textContent = text; promptEl.classList.remove("hidden"); }
    else promptEl.classList.add("hidden");
  }
  function showTutorial(text, ms = 5500) {
    if (!tutorialEl) return;
    clearTimeout(tutorialTimer);
    tutorialEl.textContent = text;
    tutorialEl.classList.remove("hidden");
    if (ms > 0) tutorialTimer = setTimeout(() => tutorialEl.classList.add("hidden"), ms);
  }
  function teachOnce(key, text, ms) {
    if (taught.has(key)) return;
    taught.add(key);
    showTutorial(text, ms);
  }
  function setControls(locked) {
    if (!controlsEl) return;
    if (locked === controlsLocked && !controlsEl.classList.contains("hidden")) return;
    controlsLocked = locked;
    controlsEl.innerHTML = `
      <span class="control-item">
        <span class="control-label">To move</span>
        <span class="arrow-keys" aria-label="Arrow keys">
          <span class="key key-up">↑</span>
          <span class="key key-left">←</span>
          <span class="key key-down">↓</span>
          <span class="key key-right">→</span>
        </span>
      </span>
      ${locked ? `
        <span class="control-item">
          <span class="control-label">To look around</span>
          <span class="mouse-hint">
            <span class="mouse-icon" aria-hidden="true"></span>
            <span>move mouse</span>
          </span>
        </span>
      ` : ""}
      <span class="control-item">
        <span class="control-label">Inspect memory</span>
        <span class="key">E</span>
      </span>
      <span class="control-item">
        <span class="control-label">Return to orbit</span>
        <span class="key">B</span>
      </span>
    `;
    controlsEl.classList.remove("hidden");
  }
  function hideControls() {
    controlsLocked = null;
    controlsEl?.classList.add("hidden");
  }

  // ---------- corruption meter ----------
  function corruptionPct() {
    return Math.min(100, Math.round(
      ((radius - START_RADIUS) / (FAIL_RADIUS - START_RADIUS)) * 100
    ));
  }
  function updateMeter() {
    const pct = restored ? 0 : corruptionPct();
    if (corruptFill) corruptFill.style.width = pct + "%";
    if (corruptPct) corruptPct.textContent = pct + "%";
    corruptMeter?.classList.toggle("is-high", !restored && pct >= 70);
    if (clueCount) clueCount.textContent = `${cluesFound()} / ${artifacts.length}`;
  }

  // ---------- the spreading wound ----------
  // Repaint terrain vertex colors around the front every frame: consumed land
  // collapses to void, with a flickering magenta band at the leading edge.
  function paintCorruption(t) {
    const cols = colAttr.array;
    const flicker = 0.75 + 0.25 * Math.sin(t * 9);
    const reach = radius + EDGE_BAND;
    for (let v = 0; v < posAttr.count; v++) {
      const d = vertDist[v];
      const i = v * 3;
      if (d >= reach) {
        if (cols[i] !== baseColors[i] || cols[i + 1] !== baseColors[i + 1]) {
          cols[i] = baseColors[i];
          cols[i + 1] = baseColors[i + 1];
          cols[i + 2] = baseColors[i + 2];
        }
        continue;
      }
      if (d <= radius) {
        // Inside the wound — sink to void, deeper toward the origin.
        const k = Math.min(1, (radius - d) / 10 + 0.45);
        cols[i] = baseColors[i] + (C_VOID[0] - baseColors[i]) * k;
        cols[i + 1] = baseColors[i + 1] + (C_VOID[1] - baseColors[i + 1]) * k;
        cols[i + 2] = baseColors[i + 2] + (C_VOID[2] - baseColors[i + 2]) * k;
      } else {
        // The leading edge — a thin magenta burn.
        const k = (1 - (d - radius) / EDGE_BAND) * flicker;
        cols[i] = baseColors[i] + (C_EDGE[0] - baseColors[i]) * k;
        cols[i + 1] = baseColors[i + 1] + (C_EDGE[1] - baseColors[i + 1]) * k;
        cols[i + 2] = baseColors[i + 2] + (C_EDGE[2] - baseColors[i + 2]) * k;
      }
    }
    colAttr.needsUpdate = true;
  }

  function updateMotes(t) {
    const arr = moteGeo.attributes.position.array;
    for (let i = 0; i < MOTES; i++) {
      const r = moteFrac[i] * radius;
      const x = ORIGIN.x + Math.cos(moteAng[i] + t * 0.05) * r;
      const z = ORIGIN.z + Math.sin(moteAng[i] + t * 0.05) * r;
      arr[i * 3] = x;
      arr[i * 3 + 1] = terrain.heightAt(x, z) + 1.2 +
        Math.sin(t * 1.6 + motePhase[i]) * 1.0 + ((t * 0.8 + motePhase[i]) % 3);
      arr[i * 3 + 2] = z;
    }
    moteGeo.attributes.position.needsUpdate = true;
    motes.material.opacity = restored ? 0 : 0.45 + 0.3 * Math.sin(t * 7);
  }

  // Sky drains toward the void as the corruption nears the terminal; a good
  // rewind lerps everything back to Level 1's calm lavender.
  function applySky() {
    if (restored || restoring) {
      const k = restoring ? Math.min(1, restoreT / RESTORE_DUR) : 1;
      scene.background.copy(SKY_SICK).lerp(SKY_HEALED, k);
      scene.fog.color.copy(FOG_SICK).lerp(SKY_HEALED, k);
      dome.material.color.copy(DOME_SICK).lerp(DOME_HEALED, k);
      sun.color.copy(SUN_SICK).lerp(SUN_HEALED, k);
      return;
    }
    let p = corruptionPct() / 100;
    if (failed) p = 1;
    p *= p;
    if (p > 0.55) p += 0.1 * (0.5 + 0.5 * Math.sin(performance.now() / 120));
    p = Math.min(1, p);
    scene.background.copy(SKY_SICK).lerp(SKY_VOID, p);
    scene.fog.color.copy(FOG_SICK).lerp(FOG_VOID, p);
    dome.material.color.copy(DOME_SICK).lerp(DOME_VOID, p);
    sun.color.copy(SUN_SICK).lerp(SUN_VOID, p * 0.9);
  }

  // ---------- briefing / fail / reset ----------
  function showBriefing() {
    fp.detach();
    tutorialEl?.classList.add("hidden");
    briefingEl?.classList.remove("hidden");
  }
  function startLevel() {
    if (started) return;
    started = true;
    briefingEl?.classList.add("hidden");
    fp.attach();
    showTutorial("The corruption is spreading from the nav panel's memory. Inspect the frozen memories (E) — their words are clues.", 8000);
  }
  briefingStartBtn?.addEventListener("click", startLevel);

  function failLevel() {
    if (failed || restored || restoring) return;
    failed = true;
    closeTerminal(false);
    closeClue();
    fp.detach();
    tutorialEl?.classList.add("hidden");
    failEl?.classList.remove("hidden");
  }
  function resetLevel() {
    failed = false;
    restored = false;
    restoring = false;
    restoreT = 0;
    radius = START_RADIUS;
    searched = false;
    lastResults = [];
    explained.clear();
    consoleDismissed = false;
    for (const a of artifacts) a.inspected = false;
    failEl?.classList.add("hidden");
    winEl?.classList.add("hidden");
    updateMeter();
    if (active) fp.attach();
    showTutorial("New attempt — find the last good checkpoint before the corruption reaches the terminal.", 6000);
  }

  // ---------- clue cards ----------
  function openClueCard(a) {
    openClue = a;
    fp.detach();
    if (!a.inspected) {
      a.inspected = true;
      updateMeter();
      if (a.clue.origin) {
        teachOnce("anomaly",
          `Anomaly time logged — ${ANOMALY}. When you explain a checkpoint, check its time against this.`, 8000);
      } else {
        teachOnce("clue",
          `Clue logged — “${a.clue.key}”. Words like this are searchable from the ship terminal.`, 7000);
      }
    }
    if (clueTitle) clueTitle.textContent = a.clue.title;
    if (clueBody) clueBody.textContent = a.clue.body;
    if (clueKey) clueKey.textContent = a.clue.key;
    clueCard?.classList.remove("hidden");
  }
  function closeClue() {
    if (!openClue) return;
    openClue = null;
    clueCard?.classList.add("hidden");
    if (active && !failed && !restored) fp.attach();
  }

  // ---------- terminal ----------
  function flashTerminal(text, ok) {
    if (!termMsg) return;
    clearTimeout(msgTimer);
    termMsg.textContent = text;
    termMsg.classList.remove("show-ok", "show-err");
    termMsg.classList.add(ok ? "show-ok" : "show-err");
    msgTimer = setTimeout(() => termMsg.classList.remove("show-ok", "show-err"), 3600);
  }

  // The next command the CTA should push the player toward.
  function suggestedCmd() {
    if (cluesFound() === 0) return null;
    if (!searched) {
      const firstClue = artifacts.find((a) => a.inspected && !a.clue.origin);
      return `entire checkpoint search "${firstClue ? firstClue.clue.key : "course plot"}"`;
    }
    if (explained.size === 0 && lastResults.length) {
      return `entire checkpoint explain ${lastResults[0].id}`;
    }
    return "entire checkpoint rewind";
  }
  function renderTerminal() {
    if (!terminalOpen) return;
    if (browserMode) return;   // the rewind browser owns the terminal until Esc/Enter
    if (confirmTarget) {
      termHint.textContent = "# rewinding is safe — you can always rewind again";
      termInput.textContent = `rewind to ${confirmTarget.id} (${confirmTarget.time})?  [y/n]`;
      termInput.classList.add("is-dim");
      if (termCta) termCta.innerHTML =
        `<span class="cta-label">PRESS</span>` +
        `<kbd class="cta-key cta-key-yes">Y</kbd><span class="cta-note">rewind</span>` +
        `<kbd class="cta-key cta-key-no">N</kbd><span class="cta-note">cancel</span>`;
      return;
    }
    termInput.classList.remove("is-dim");
    termInput.textContent = buffer;
    const cmd = suggestedCmd();
    if (!cmd) {
      termHint.textContent = "# the log is searchable — but you need words to search for";
      if (termCta) termCta.innerHTML =
        `<span class="cta-label">FIRST</span>` +
        `<span class="cta-note">inspect the frozen memories — walk up, press E</span>`;
    } else {
      const why = !searched
        ? "Search the ship's checkpoint log for the words you found"
        : explained.size === 0
          ? "Explain a candidate — was it written before or after the anomaly?"
          : "Browse the checkpoints and rewind to the last good one";
      termHint.textContent = `# ${why}`;
      if (termCta) termCta.innerHTML =
        `<span class="cta-label">TYPE</span><span class="cta-cmd">${cmd}</span>`;
    }
  }
  function openTerminal() {
    if (terminalOpen) return;
    terminalOpen = true;
    buffer = "";
    fp.detach();
    termMsg?.classList.remove("show-ok", "show-err");
    termList?.classList.add("hidden");
    termEl?.classList.remove("hidden");
    teachOnce("terminal",
      "The ship terminal reads the checkpoint log — every memory you've ever banked. Search it, explain it, rewind it.", 7500);
    renderTerminal();
  }
  function closeTerminal(dismiss) {
    if (!terminalOpen) return;
    if (dismiss) consoleDismissed = true;
    terminalOpen = false;
    buffer = "";
    browserMode = false;
    confirmTarget = null;
    termEl?.classList.add("hidden");
    termList?.classList.add("hidden");
    if (active && !failed && !restored && !restoring) fp.attach();
  }

  // ---------- entire checkpoint search ----------
  function doSearch(raw) {
    const q = raw.replace(/^.*?search/i, "").replace(/["']/g, "").trim().toLowerCase();
    const words = q.split(/\s+/).filter((w) => w.length >= 3);
    if (!words.length) {
      flashTerminal('search needs words — try:  entire checkpoint search "course plot"', false);
      return;
    }
    const scored = CHECKPOINTS
      .map((cp) => ({
        cp,
        score: words.filter((w) => cp.summary.toLowerCase().includes(w)).length,
      }))
      .filter((r) => r.score > 0)
      .sort((a, b) => b.score - a.score || (a.cp.time < b.cp.time ? 1 : -1));
    if (!scored.length) {
      flashTerminal(`0 results for “${q}” — try words from the memories you inspected`, false);
      return;
    }
    searched = true;
    lastResults = scored.map((r) => r.cp);
    if (termList) {
      termList.innerHTML = lastResults.map((cp) =>
        `<div class="term-list-row"><span class="tl-id">${cp.id}</span>` +
        `<span class="tl-time">${cp.time}</span>` +
        `<span class="tl-title">${cp.summary}</span></div>`
      ).join("");
      termList.classList.remove("hidden");
    }
    flashTerminal(`${lastResults.length} checkpoint${lastResults.length === 1 ? "" : "s"} matched “${q}”`, true);
    teachOnce("searched",
      "Each result is a moment you can return to. `entire checkpoint explain <id>` shows what's inside one.", 8000);
  }

  // ---------- entire checkpoint explain ----------
  function doExplain(n) {
    const token = n.replace(/^.*?explain/i, "").trim().split(/\s+/)[0] || "";
    if (token.length < 4) {
      flashTerminal("explain needs a checkpoint id — copy one from the search results", false);
      return;
    }
    const cp = CHECKPOINTS.find((c) => c.id.startsWith(token.toLowerCase()));
    if (!cp) {
      flashTerminal(`no checkpoint matching “${token}” — copy an id from the search results`, false);
      return;
    }
    explained.add(cp.id);
    if (termList) {
      const rows = [
        ["checkpoint", cp.id],
        ["time", cp.time],
        ["summary", cp.summary],
        ["files", cp.files],
        ["session", cp.session],
      ];
      termList.innerHTML = rows.map(([k, v]) =>
        `<div class="term-list-row"><span class="tl-key tl-exp-key">${k}</span>` +
        `<span class="tl-title">${v}</span></div>`
      ).join("") + (anomalyKnown()
        ? `<div class="term-list-row"><span class="tl-key tl-exp-key">#</span>` +
          `<span class="tl-anomaly">anomaly began ${ANOMALY} — is ${cp.time} before or after?</span></div>`
        : "");
      termList.classList.remove("hidden");
    }
    flashTerminal(`explained ${cp.id}`, true);
    teachOnce("explained",
      "Explain shows the session behind a checkpoint — when, what, and why. Compare times. Then `entire checkpoint rewind`.", 8000);
  }

  // ---------- entire checkpoint rewind ----------
  function openBrowser() {
    browserMode = true;
    browserSel = 0;
    renderBrowser();
    teachOnce("browser",
      "The rewind browser lists every checkpoint, newest first. ↑/↓ to choose, Enter to rewind, Esc to cancel.", 8000);
  }
  function renderBrowser() {
    termHint.textContent = "# entire checkpoint rewind — choose where to return to";
    termInput.textContent = "entire checkpoint rewind";
    termInput.classList.add("is-dim");
    if (termCta) termCta.innerHTML =
      `<span class="cta-label">KEYS</span>` +
      `<span class="cta-note">↑/↓ choose · Enter rewind · Esc cancel</span>`;
    if (termList) {
      termList.innerHTML = browserList().map((cp, i) =>
        `<div class="term-list-row${i === browserSel ? " is-sel" : ""}">` +
        `<span class="tl-sel">${i === browserSel ? "▸" : " "}</span>` +
        `<span class="tl-id">${cp.id}</span>` +
        `<span class="tl-time">${cp.time}</span>` +
        `<span class="tl-title">${cp.summary}</span></div>`
      ).join("");
      termList.classList.remove("hidden");
    }
  }
  function applyRewind(cp) {
    confirmTarget = null;
    termInput.classList.remove("is-dim");
    if (cp.good) {
      startRestore(cp);
      return;
    }
    // Soft fail — the wrong moment. The corruption surges, but rewinding is
    // safe and repeatable: that's the whole lesson.
    radius = Math.min(radius + SURGE, FAIL_RADIUS + 0.1);
    glitchFlash?.classList.remove("show");
    void glitchFlash?.offsetWidth;   // restart the flash animation
    glitchFlash?.classList.add("show");
    flashTerminal(
      `rewound to ${cp.id} — still corrupted. it was written ${cp.time}, after the anomaly. rewind again — rewinding is always safe.`,
      false
    );
    termList?.classList.add("hidden");
    buffer = "";
    renderTerminal();
  }
  function startRestore(cp) {
    restoring = true;
    restoreT = 0;
    restoreFrom = radius;
    closeTerminal(false);
    fp.detach();
    if (winSub) winSub.textContent = `rewound to ${cp.id} · ${cp.summary}`;
    showTutorial(`Rewinding to ${cp.id} — ${cp.time}, the last good moment…`, 0);
  }
  function finishRestore() {
    restoring = false;
    restored = true;
    radius = 0;
    updateMeter();
    tutorialEl?.classList.add("hidden");
    winEl?.classList.remove("hidden");
    if (active) fp.attach();
  }

  // ---------- command dispatch ----------
  function submitCommand() {
    const n = normalizeCmd(buffer);
    buffer = "";
    if (!n) { renderTerminal(); return; }
    if (/^entire (checkpoint|cp) search\b/.test(n)) doSearch(n);
    else if (/^entire (checkpoint|cp) explain\b/.test(n)) doExplain(n);
    else if (/^entire (checkpoint|cp) rewind\b/.test(n)) { openBrowser(); return; }
    else if (/^entire (checkpoint|cp) list$/.test(n)) {
      if (termList) {
        termList.innerHTML = browserList().map((cp) =>
          `<div class="term-list-row"><span class="tl-id">${cp.id}</span>` +
          `<span class="tl-time">${cp.time}</span>` +
          `<span class="tl-title">${cp.summary}</span></div>`
        ).join("");
        termList.classList.remove("hidden");
      }
      flashTerminal("the full log — search finds the ones that matter", true);
    } else {
      const cmd = suggestedCmd();
      flashTerminal(`command not recognized${cmd ? ` — try:  ${cmd}` : " — inspect the memories for clues first"}`, false);
    }
    renderTerminal();
  }

  // ---------- input ----------
  function onCanvasClick() {
    if (!started || failed) return;
    if (active && !fp.isLocked && !terminalOpen && !openClue) fp.lock();
  }
  function onKeyDown(e) {
    if (!active) return;

    // Briefing is up — Enter/Space begins the run, nothing else.
    if (!started) {
      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
      return;
    }

    // The corruption won — only R (retry) does anything.
    if (failed) {
      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
      return;
    }

    // Reading a clue — E or Esc puts it down.
    if (openClue) {
      if (e.code === "KeyE" || e.code === "Escape") { closeClue(); e.preventDefault(); }
      return;
    }

    // While the terminal is open, all keys feed it.
    if (terminalOpen) {
      if (confirmTarget) {
        if (e.key === "y" || e.key === "Y") { applyRewind(confirmTarget); e.preventDefault(); return; }
        if (e.key === "n" || e.key === "N" || e.code === "Escape") {
          confirmTarget = null;
          openBrowser();             // back to the browser, nothing lost
          e.preventDefault();
          return;
        }
        e.preventDefault();
        return;
      }
      if (browserMode) {
        const list = browserList();
        if (e.code === "ArrowUp") { browserSel = (browserSel + list.length - 1) % list.length; renderBrowser(); e.preventDefault(); return; }
        if (e.code === "ArrowDown") { browserSel = (browserSel + 1) % list.length; renderBrowser(); e.preventDefault(); return; }
        if (e.code === "Enter") {
          browserMode = false;
          confirmTarget = list[browserSel];
          termList?.classList.add("hidden");
          renderTerminal();
          e.preventDefault();
          return;
        }
        if (e.code === "Escape") {
          browserMode = false;
          termInput.classList.remove("is-dim");
          termList?.classList.add("hidden");
          renderTerminal();
          e.preventDefault();
          return;
        }
        e.preventDefault();
        return;
      }
      if (e.code === "Escape") { closeTerminal(true); e.preventDefault(); return; }
      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
        buffer += e.key;
        renderTerminal();
        e.preventDefault();
      }
      return;
    }

    // Walking around.
    if (e.code === "KeyE" && nearArtifact) { openClueCard(nearArtifact); e.preventDefault(); return; }
    if (e.code === "Escape" && fp.isLocked) fp.unlock();
    if (e.code === "KeyB") onExit?.();
  }
  fp.controls.addEventListener("lock", () => crosshair?.classList.remove("hidden"));
  fp.controls.addEventListener("unlock", () => crosshair?.classList.add("hidden"));

  // ---------- HUD per-frame ----------
  let nearArtifact = null;
  let nearConsole = false;

  function refreshHud() {
    if (!started || terminalOpen || openClue) {
      setPrompt(null);
      hideControls();
      return;
    }
    setControls(fp.isLocked);
    if (!fp.isLocked) { setPrompt("Click to look around"); return; }
    if (restored) { setPrompt("Timeline restored — press B to return to orbit"); return; }
    if (restoring) { setPrompt(null); return; }
    if (nearArtifact) {
      setPrompt(nearArtifact.inspected
        ? "Press E — review the clue"
        : "Press E — inspect the frozen memory");
      return;
    }
    const found = cluesFound();
    if (found === 0) setPrompt("Find the frozen memories — their words are clues");
    else if (found < artifacts.length) setPrompt("More clues remain — or head for the cyan beam: the ship terminal");
    else setPrompt("Head for the cyan beam — the ship terminal");
  }

  // ---------- per-frame ----------
  function update(dt, t) {
    fp.update(dt);

    // The corruption spreads while the run is live.
    if (active && started && !failed && !restoring && !restored) {
      radius += SPREAD_RATE * dt;
      if (radius >= FAIL_RADIUS) failLevel();
      updateMeter();
    }

    // A good rewind pulls the wound back to nothing.
    if (restoring) {
      restoreT += dt;
      const k = Math.min(1, restoreT / RESTORE_DUR);
      radius = restoreFrom * (1 - k * k);   // accelerating retreat
      updateMeter();
      if (restoreT >= RESTORE_DUR) finishRestore();
    }

    if (active) {
      paintCorruption(t);
      updateMotes(t);
      applySky();
    }

    // Artifacts: gentle glow while safe; glitch-jitter once the wound has them.
    for (const a of artifacts) {
      const consumed = a.distFromOrigin <= radius + EDGE_BAND;
      const sick = a.clue.origin || consumed;
      if (sick && !restored && !restoring) {
        const j = a.clue.origin ? 0.22 : 0.12;
        a.ice.position.x = a.iceBaseX + (Math.random() - 0.5) * j;
        a.ice.position.y = a.iceBaseY + (Math.random() - 0.5) * j * 0.5;
        const blink = Math.sin(t * (a.clue.origin ? 14 : 9)) > 0;
        a.ice.material.emissive.setHex(blink ? 0xa6126e : 0x123a4a);
        a.ice.material.emissiveIntensity = 1.3;
        a.glow.color.setHex(blink ? 0xff2bd6 : 0x8fe3ff);
      } else {
        a.ice.position.x = a.iceBaseX;
        a.ice.position.y = a.iceBaseY;
        a.ice.material.emissive.setHex(0x2a6c8a);
        a.ice.material.emissiveIntensity = 1.1;
        a.glow.color.setHex(0x8fe3ff);
      }
    }

    // The console screen flickers harder as the corruption closes in.
    const screen = consoleProp.userData.screen;
    if (screen) {
      const closeness = Math.min(1, radius / FAIL_RADIUS);
      const flick = Math.sin(t * (6 + closeness * 18)) > -0.2 + closeness * 0.8;
      screen.material.emissive.setHex(
        restored || restoring ? 0x2a8aa6 : flick ? 0x2a8aa6 : 0xa6126e
      );
    }

    // Proximity: nearest inspectable memory, and the ship terminal.
    nearArtifact = null;
    let nd = Infinity;
    for (const a of artifacts) {
      const d = Math.hypot(
        camera.position.x - a.anchor.position.x,
        camera.position.z - a.anchor.position.z
      );
      if (d < nd) { nd = d; if (d <= INTERACT_DIST) nearArtifact = a; }
    }
    nearConsole = Math.hypot(
      camera.position.x - CONSOLE_POS.x, camera.position.z - CONSOLE_POS.z
    ) <= CONSOLE_DIST;

    // The terminal opens itself when you reach the console, like Level 1.
    if (active && started && !failed && !restoring && !restored && !openClue) {
      if (consoleDismissed && !nearConsole) consoleDismissed = false;
      if (nearConsole && !terminalOpen && !consoleDismissed) openTerminal();
      else if (!nearConsole && terminalOpen) closeTerminal(false);
    }

    if (terminalOpen && !browserMode && !confirmTarget) renderTerminal();
    if (active) refreshHud();
  }

  // ---------- lifecycle ----------
  function enter() {
    active = true;
    fp.groundAt(0, terrain.radius * 0.75);
    camera.lookAt(CONSOLE_POS.x, terrain.heightAt(CONSOLE_POS.x, CONSOLE_POS.z) + 5, CONSOLE_POS.z);
    canvas.addEventListener("click", onCanvasClick);
    window.addEventListener("keydown", onKeyDown);
    l2Hud?.classList.remove("hidden");
    fpShared?.classList.remove("hidden");
    setControls(false);
    crosshair?.classList.add("hidden");
    updateMeter();
    if (!started) {
      showBriefing();
    } else if (restored) {
      fp.attach();
      showTutorial("Timeline restored — press B to return to orbit.", 0);
    } else if (failed) {
      resetLevel();                 // came back after a wipe → fresh run
    } else {
      fp.attach();
      showTutorial("The corruption never stopped. Find the last good checkpoint.", 6000);
    }
  }
  function exit() {
    active = false;
    closeTerminal(false);
    closeClue();
    fp.unlock();
    fp.detach();
    canvas.removeEventListener("click", onCanvasClick);
    window.removeEventListener("keydown", onKeyDown);
    setPrompt(null);
    hideControls();
    tutorialEl?.classList.add("hidden");
    termEl?.classList.add("hidden");
    failEl?.classList.add("hidden");
    winEl?.classList.add("hidden");
    briefingEl?.classList.add("hidden");
    clueCard?.classList.add("hidden");
    l2Hud?.classList.add("hidden");
    fpShared?.classList.add("hidden");
    crosshair?.classList.add("hidden");
  }
  function resize() {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
  }

  return { scene, camera, update, enter, exit, resize };
}

