1	import * as THREE from "three";
2	import { PointerLockControls } from "three/addons/controls/PointerLockControls.js";
3	
4	// First-person walker: PointerLockControls for mouse-look + keyboard movement
5	// that hugs the terrain. Click the canvas to look around; Escape releases the mouse.
6	
7	export function createFirstPerson(camera, domElement, {
8	  heightAt,
9	  radius = 80,        // keep the walker on the island, not out at sea
10	  eyeHeight = 2.4,
11	  speed = 22,         // world units / second
12	} = {}) {
