const terrain = createTerrain({ size: 200, segments: 220, maxHeight: 26, seed: 1337 });
function mulberry32(seed){return function(){seed|=0;seed=(seed+0x6d2b79f5)|0;let t=Math.imul(seed^(seed>>>15),1|seed);t=(t+Math.imul(t^(t>>>7),61|t))^t;return((t^(t>>>14))>>>0)/4294967296;};}
const CONSOLE_POS={x:-6,z:56};
const rand=mulberry32(20260609);
const placements=[];let spacing=13,tries=0,total=0;
while(placements.length<21){
  total++;
  if(++tries>3000){spacing=Math.max(6,spacing-2);tries=0;}
  const ang=rand()*Math.PI*2, r=16+rand()*56;
  const x=Math.cos(ang)*r, z=Math.sin(ang)*r;
  if(terrain.heightAt(x,z)<1.8)continue;
  if(Math.hypot(x-CONSOLE_POS.x,z-CONSOLE_POS.z)<14)continue;
  if(placements.some((p)=>Math.hypot(x-p.x,z-p.z)<spacing))continue;
  placements.push({x,z});
}
const hs=placements.map(p=>terrain.heightAt(p.x,p.z));
let minPair=Infinity;
for(let i=0;i<21;i++)for(let j=i+1;j<21;j++)minPair=Math.min(minPair,Math.hypot(placements[i].x-placements[j].x,placements[i].z-placements[j].z));
console.log('placed:',placements.length,'attempts:',total,'final spacing:',spacing);
console.log('height min/max:',Math.min(...hs).toFixed(2),Math.max(...hs).toFixed(2));
console.log('closest pair:',minPair.toFixed(1),'min dist to console:',Math.min(...placements.map(p=>Math.hypot(p.x-CONSOLE_POS.x,p.z-CONSOLE_POS.z))).toFixed(1));
